/**
 * DiagnosticsPanel — Displays compilation errors, warnings, and info messages.
 *
 * Clicking a diagnostic item navigates to the error location in the editor.
 */
import type { Diagnostic, DiagnosticSeverity } from '../../types';
import styles from './DiagnosticsPanel.module.css';

interface DiagnosticsPanelProps {
  /** List of diagnostics from compilation */
  diagnostics: readonly Diagnostic[];
  /** Called when user clicks a diagnostic to navigate to its location */
  onNavigate?: (line: number, column: number) => void;
  /** Called when user closes the panel */
  onClose?: () => void;
}

const SEVERITY_ICONS: Record<DiagnosticSeverity, string> = {
  error: '\u2716',   // heavy X
  warning: '\u26A0', // warning sign
  info: '\u2139',    // info sign
  hint: '\u2731',    // heavy asterisk
};

const SEVERITY_LABELS: Record<DiagnosticSeverity, string> = {
  error: 'Error',
  warning: 'Warning',
  info: 'Info',
  hint: 'Hint',
};

function severityStyle(severity: DiagnosticSeverity): string {
  switch (severity) {
    case 'error': return styles.severityError;
    case 'warning': return styles.severityWarning;
    case 'info': return styles.severityInfo;
    case 'hint': return styles.severityHint;
  }
}

function badgeStyle(severity: DiagnosticSeverity): string {
  switch (severity) {
    case 'error': return styles.badgeError;
    case 'warning': return styles.badgeWarning;
    default: return styles.badgeInfo;
  }
}

export function DiagnosticsPanel({
  diagnostics,
  onNavigate,
  onClose,
}: DiagnosticsPanelProps) {
  const errorCount = diagnostics.filter((d) => d.severity === 'error').length;
  const warningCount = diagnostics.filter((d) => d.severity === 'warning').length;

  const handleItemClick = (diag: Diagnostic) => {
    // Don't navigate if the user is selecting text (would steal focus).
    const selection = window.getSelection();
    if (selection && selection.toString().length > 0) return;
    onNavigate?.(diag.startLine, diag.startColumn);
  };

  const handleItemKeyDown = (event: React.KeyboardEvent, diag: Diagnostic) => {
    if (event.key === 'Enter' || event.key === ' ') {
      event.preventDefault();
      onNavigate?.(diag.startLine, diag.startColumn);
    }
    // Ctrl+C / Cmd+C: copy the diagnostic message text
    if ((event.ctrlKey || event.metaKey) && event.key === 'c') {
      const selection = window.getSelection();
      if (!selection || selection.toString().length === 0) {
        // Nothing selected — copy the full message
        event.preventDefault();
        void navigator.clipboard.writeText(diag.message);
      }
      // If text is selected, let the browser's default copy behavior handle it
    }
  };

  return (
    <div
      className={styles.panel}
      role="region"
      aria-label="Diagnostics panel"
    >
      <div className={styles.header}>
        <span className={styles.headerTitle}>Problems</span>
        {errorCount > 0 && (
          <span className={`${styles.badge} ${badgeStyle('error')}`} aria-label={`${errorCount} errors`}>
            {errorCount}
          </span>
        )}
        {warningCount > 0 && (
          <span className={`${styles.badge} ${badgeStyle('warning')}`} aria-label={`${warningCount} warnings`}>
            {warningCount}
          </span>
        )}
        {onClose && (
          <button
            className={styles.closeButton}
            onClick={onClose}
            aria-label="Close diagnostics panel"
            type="button"
          >
            {'\u2715'}
          </button>
        )}
      </div>

      {diagnostics.length === 0 ? (
        <div className={styles.empty} role="status">
          No problems detected
        </div>
      ) : (
        <div className={styles.list} role="group" aria-label="Diagnostic messages">
          {diagnostics.map((diag, index) => (
            <div
              key={`${diag.startLine}-${diag.startColumn}-${index}`}
              className={styles.item}
              onClick={() => handleItemClick(diag)}
              onKeyDown={(e) => handleItemKeyDown(e, diag)}
              role="button"
              tabIndex={0}
              aria-label={`${SEVERITY_LABELS[diag.severity]}: ${diag.message} at line ${diag.startLine}`}
            >
              <span
                className={`${styles.severityIcon} ${severityStyle(diag.severity)}`}
                aria-hidden="true"
              >
                {SEVERITY_ICONS[diag.severity]}
              </span>
              <div className={styles.itemContent}>
                <div className={styles.itemMessage}>{diag.message}</div>
                <div className={styles.itemLocation}>
                  Ln {diag.startLine}, Col {diag.startColumn}
                  {diag.code ? ` [${diag.code}]` : ''}
                </div>
                {diag.suggestion && (
                  <div className={styles.itemSuggestion}>{diag.suggestion}</div>
                )}
              </div>
            </div>
          ))}
        </div>
      )}
    </div>
  );
}
