/**
 * useFdc3 — FDC3 context listener and broadcast integration.
 *
 * When running inside DeskModal (window.fdc3 available):
 * - Listens for `fdc3.instrument` context, extracts ticker/RIC
 * - Provides broadcast helpers for plot data and backtest results
 *
 * In standalone browser mode, all operations are no-ops.
 */
import { useState, useEffect, useCallback, useRef } from 'react';

export interface Fdc3State {
  /** Currently active instrument symbol (e.g. "AAPL", "EUR/USD") */
  activeInstrument: string | null;
  /** Whether FDC3 API is available */
  isConnected: boolean;
  /** Current channel name, if any */
  channelId: string | null;
}

export interface Fdc3Actions {
  /** Broadcast plot data after a successful run */
  broadcastPlotData: (
    plots: readonly { barIndex: number; plotId: number; value: number }[],
    scriptName: string,
  ) => void;
  /** Broadcast backtest results */
  broadcastBacktestResult: (result: {
    scriptName: string;
    instrument: string;
    netProfit: number;
    netProfitPercent: number;
    totalTrades: number;
    winRate: number;
    maxDrawdown: number;
    sharpeRatio: number;
  }) => void;
}

export interface UseFdc3Result {
  state: Fdc3State;
  actions: Fdc3Actions;
}

export function useFdc3(): UseFdc3Result {
  const [activeInstrument, setActiveInstrument] = useState<string | null>(null);
  const [isConnected, setIsConnected] = useState(false);
  const [channelId, setChannelId] = useState<string | null>(null);
  const listenerRef = useRef<{ unsubscribe: () => void } | null>(null);

  useEffect(() => {
    const fdc3 = window.fdc3;
    if (!fdc3) {
      setIsConnected(false);
      return;
    }

    setIsConnected(true);

    // Query current channel and its last instrument context
    fdc3.getCurrentChannel()
      .then((channel) => {
        if (channel) {
          setChannelId(channel.id);
          // Fetch the last broadcast instrument context on this channel.
          // This catches instruments selected BEFORE OptiScript was opened.
          channel.getCurrentContext('fdc3.instrument')
            .then((ctx) => {
              if (ctx) {
                const ticker = ctx.id?.ticker ?? ctx.id?.RIC ?? ctx.id?.ISIN ?? null;
                if (ticker) setActiveInstrument(ticker);
              }
            })
            .catch(() => { /* non-fatal */ });
        }
      })
      .catch(() => {
        // Channel query failed — non-fatal
      });

    // Register instrument context listener (fires on NEW broadcasts)
    const listenerResult = fdc3.addContextListener(
      'fdc3.instrument',
      (context: Fdc3Context) => {
        const ticker = context.id?.ticker ?? context.id?.RIC ?? context.id?.ISIN ?? null;
        if (ticker) {
          setActiveInstrument(ticker);
        }
      },
    );

    // addContextListener may return a Promise or a sync listener
    if (listenerResult && 'then' in listenerResult) {
      listenerResult.then((listener) => {
        listenerRef.current = listener;
      }).catch(() => {
        // Listener registration failed
      });
    } else if (listenerResult) {
      listenerRef.current = listenerResult;
    }

    return () => {
      listenerRef.current?.unsubscribe();
      listenerRef.current = null;
    };
  }, []);

  const broadcastPlotData = useCallback(
    (
      plots: readonly { barIndex: number; plotId: number; value: number }[],
      scriptName: string,
    ) => {
      const fdc3 = window.fdc3;
      if (!fdc3) return;

      try {
        void fdc3.broadcast({
          type: 'optiscript.plot-data',
          plots: plots as unknown as Fdc3Context['plots'],
          scriptName,
        } as Fdc3Context);
      } catch {
        // Broadcast failure is non-fatal
      }
    },
    [],
  );

  const broadcastBacktestResult = useCallback(
    (result: {
      scriptName: string;
      instrument: string;
      netProfit: number;
      netProfitPercent: number;
      totalTrades: number;
      winRate: number;
      maxDrawdown: number;
      sharpeRatio: number;
    }) => {
      const fdc3 = window.fdc3;
      if (!fdc3) return;

      try {
        void fdc3.broadcast({
          type: 'optiscript.backtest-result',
          ...result,
        } as Fdc3Context);
      } catch {
        // Broadcast failure is non-fatal
      }
    },
    [],
  );

  return {
    state: { activeInstrument, isConnected, channelId },
    actions: { broadcastPlotData, broadcastBacktestResult },
  };
}
