/**
 * RunOutput — displays plot values and execution metadata after running a script.
 */
import styles from './RunOutput.module.css';

export interface PlotPoint {
  readonly barIndex: number;
  readonly plotId: number;
  readonly value: number;
}

export interface RunResult {
  readonly success: boolean;
  readonly barCount: number;
  readonly executionTimeMs: number;
  readonly plotOutputs: readonly PlotPoint[];
}

interface RunOutputProps {
  result: RunResult;
  onClose: () => void;
}

/** Group plot outputs by plotId, return sorted by barIndex. */
function groupByPlot(
  outputs: readonly PlotPoint[],
): Map<number, PlotPoint[]> {
  const map = new Map<number, PlotPoint[]>();
  for (const pt of outputs) {
    let arr = map.get(pt.plotId);
    if (!arr) {
      arr = [];
      map.set(pt.plotId, arr);
    }
    arr.push(pt);
  }
  // Sort each group by barIndex
  for (const arr of map.values()) {
    arr.sort((a, b) => a.barIndex - b.barIndex);
  }
  return map;
}

function formatValue(v: number): string {
  if (Number.isNaN(v)) return 'NaN';
  if (!Number.isFinite(v)) return v > 0 ? '+Inf' : '-Inf';
  // Show up to 6 decimal places, trim trailing zeros
  return v.toFixed(6).replace(/\.?0+$/, '');
}

export function RunOutput({ result, onClose }: RunOutputProps) {
  const grouped = groupByPlot(result.plotOutputs);
  const plotIds = Array.from(grouped.keys()).sort((a, b) => a - b);

  // Build a table: rows = bar indices, columns = plot IDs
  const allBarIndices = new Set<number>();
  for (const pts of grouped.values()) {
    for (const pt of pts) allBarIndices.add(pt.barIndex);
  }
  const barIndices = Array.from(allBarIndices).sort((a, b) => a - b);

  // Build lookup: (barIndex, plotId) -> value
  const lookup = new Map<string, number>();
  for (const [plotId, pts] of grouped) {
    for (const pt of pts) {
      lookup.set(`${pt.barIndex}:${plotId}`, pt.value);
    }
  }

  return (
    <div className={styles.panel} role="region" aria-label="Run output">
      <div className={styles.header}>
        <div className={styles.headerLeft}>
          <span className={styles.title}>Output</span>
          <span className={result.success ? styles.successBadge : styles.errorBadge}>
            {result.success ? 'OK' : 'Error'}
          </span>
        </div>
        <div className={styles.headerRight}>
          <span className={styles.meta}>
            {result.barCount} bars &middot; {plotIds.length} plot{plotIds.length !== 1 ? 's' : ''} &middot; {result.executionTimeMs.toFixed(1)}ms
          </span>
          <button
            className={styles.closeBtn}
            onClick={onClose}
            aria-label="Close output panel"
            type="button"
          >
            &times;
          </button>
        </div>
      </div>

      <div className={styles.body}>
        {barIndices.length === 0 ? (
          <div className={styles.empty}>No plot output. Add plot() calls to your script.</div>
        ) : (
          <table className={styles.table}>
            <thead>
              <tr>
                <th>Bar</th>
                {plotIds.map((id) => (
                  <th key={id}>Plot {id}</th>
                ))}
              </tr>
            </thead>
            <tbody>
              {barIndices.map((barIdx) => (
                <tr key={barIdx}>
                  <td>{barIdx}</td>
                  {plotIds.map((plotId) => {
                    const key = `${barIdx}:${plotId}`;
                    const val = lookup.get(key);
                    if (val === undefined || Number.isNaN(val)) {
                      return (
                        <td key={plotId} className={styles.naValue}>
                          na
                        </td>
                      );
                    }
                    return <td key={plotId}>{formatValue(val)}</td>;
                  })}
                </tr>
              ))}
            </tbody>
          </table>
        )}
      </div>
    </div>
  );
}
