/**
 * OptiEditor — Main editor component wrapping Monaco Editor.
 *
 * Integrates OptiScript syntax highlighting, auto-completion, hover docs,
 * and inline error diagnostics via Monaco markers.
 */
import { useEffect, useRef, useCallback, useState, forwardRef, useImperativeHandle } from 'react';
import * as monacoApi from 'monaco-editor';
import {
  createOptiScriptLanguage,
  createOptiScriptLanguageConfiguration,
  createOptiScriptDarkTheme,
  createOptiScriptLightTheme,
  createCompletionProvider,
  createHoverProvider,
  createSignatureHelpProvider,
  createDocumentSymbolProvider,
  detectVersion,
} from '../../languages';
import { useTheme } from '../../hooks';
import type { OptiVersion, Diagnostic } from '../../types';
import styles from './OptiEditor.module.css';

const LANGUAGE_ID = 'optiscript';

/** Whether the language has been registered globally */
let languageRegistered = false;

/** Methods exposed to parent components via ref */
export interface OptiEditorRef {
  getEditor: () => monacoApi.editor.IStandaloneCodeEditor | null;
  getCursorLine: () => number;
  revealLine: (line: number) => void;
  setBreakpointDecorations: (lines: number[]) => void;
  setCurrentLineDecoration: (line: number | null) => void;
}

/** An inline debug value to display at the end of a line in the editor */
export interface InlineDebugValue {
  readonly line: number;
  readonly text: string;
}

interface OptiEditorProps {
  /** Initial source code */
  value: string;
  /** Called on every content change */
  onChange: (value: string) => void;
  /** Called when the detected version changes */
  onVersionChange?: (version: OptiVersion) => void;
  /** Diagnostics to display as Monaco markers */
  diagnostics?: readonly Diagnostic[];
  /** Whether the editor is read-only */
  readOnly?: boolean;
  /** Override the detected version */
  version?: OptiVersion;
  /** Called when user clicks the glyph margin to toggle a breakpoint */
  onBreakpointToggle?: (line: number) => void;
  /** Lines with active breakpoints (red glyph markers) */
  breakpointLines?: number[];
  /** Line where debugger is currently paused (yellow highlight) */
  currentDebugLine?: number | null;
  /** Inline variable values to display at the end of source lines when debugging */
  inlineDebugValues?: readonly InlineDebugValue[];
}

function registerLanguage(): void {
  if (languageRegistered) return;
  languageRegistered = true;

  monacoApi.languages.register({ id: LANGUAGE_ID });
  monacoApi.languages.setLanguageConfiguration(
    LANGUAGE_ID,
    createOptiScriptLanguageConfiguration(),
  );

  // Register themes
  monacoApi.editor.defineTheme('optiscript-dark', createOptiScriptDarkTheme());
  monacoApi.editor.defineTheme('optiscript-light', createOptiScriptLightTheme());
}

export const OptiEditor = forwardRef<OptiEditorRef, OptiEditorProps>(function OptiEditor({
  value,
  onChange,
  onVersionChange,
  diagnostics,
  readOnly = false,
  version: versionOverride,
  onBreakpointToggle,
  breakpointLines,
  currentDebugLine,
  inlineDebugValues,
}: OptiEditorProps, ref) {
  const containerRef = useRef<HTMLDivElement>(null);
  const editorRef = useRef<monacoApi.editor.IStandaloneCodeEditor | null>(null);
  const versionRef = useRef<OptiVersion>(versionOverride ?? detectVersion(value));
  const [currentVersion, setCurrentVersion] = useState<OptiVersion>(
    versionOverride ?? detectVersion(value),
  );
  const theme = useTheme();
  const disposablesRef = useRef<monacoApi.IDisposable[]>([]);
  const breakpointDecorationsRef = useRef<string[]>([]);
  const currentLineDecorationRef = useRef<string[]>([]);
  const inlineValueDecorationsRef = useRef<string[]>([]);

  // Expose imperative methods via ref
  useImperativeHandle(ref, () => ({
    getEditor: () => editorRef.current,
    getCursorLine: () => {
      const editor = editorRef.current;
      if (!editor) return 1;
      return editor.getPosition()?.lineNumber ?? 1;
    },
    revealLine: (line: number) => {
      editorRef.current?.revealLineInCenter(line);
    },
    setBreakpointDecorations: (lines: number[]) => {
      const editor = editorRef.current;
      if (!editor) return;
      breakpointDecorationsRef.current = editor.deltaDecorations(
        breakpointDecorationsRef.current,
        lines.map((ln) => ({
          range: new monacoApi.Range(ln, 1, ln, 1),
          options: {
            isWholeLine: false,
            glyphMarginClassName: 'optiscript-breakpoint-glyph',
            stickiness: monacoApi.editor.TrackedRangeStickiness.NeverGrowsWhenTypingAtEdges,
          },
        })),
      );
    },
    setCurrentLineDecoration: (line: number | null) => {
      const editor = editorRef.current;
      if (!editor) return;
      currentLineDecorationRef.current = editor.deltaDecorations(
        currentLineDecorationRef.current,
        line != null
          ? [{
              range: new monacoApi.Range(line, 1, line, 1),
              options: {
                isWholeLine: true,
                className: 'optiscript-current-line-highlight',
                stickiness: monacoApi.editor.TrackedRangeStickiness.NeverGrowsWhenTypingAtEdges,
              },
            }]
          : [],
      );
    },
  }));

  // Update version ref when override changes
  useEffect(() => {
    if (versionOverride !== undefined) {
      versionRef.current = versionOverride;
      setCurrentVersion(versionOverride);
    }
  }, [versionOverride]);

  // Monaco theme selection based on app theme
  const monacoTheme = theme === 'light' ? 'optiscript-light' : 'optiscript-dark';

  // Initialize editor
  useEffect(() => {
    if (!containerRef.current) return;

    registerLanguage();

    const editor = monacoApi.editor.create(containerRef.current, {
      value,
      language: LANGUAGE_ID,
      theme: monacoTheme,
      automaticLayout: true,
      fontSize: 13,
      fontFamily: "var(--deskmodal-font-mono), 'JetBrains Mono', 'Fira Code', monospace",
      lineHeight: 20,
      minimap: { enabled: true, scale: 1, renderCharacters: false },
      scrollBeyondLastLine: false,
      renderLineHighlight: 'line',
      cursorBlinking: 'smooth',
      cursorSmoothCaretAnimation: 'on',
      smoothScrolling: true,
      tabSize: 4,
      insertSpaces: true,
      wordWrap: 'off',
      bracketPairColorization: { enabled: true },
      guides: { bracketPairs: true, indentation: true },
      glyphMargin: true,
      padding: { top: 8 },
      readOnly,
      accessibilitySupport: 'on',
      ariaLabel: 'OptiScript code editor',
    });

    editorRef.current = editor;

    // Set up Monarch tokenizer for the current version
    monacoApi.languages.setMonarchTokensProvider(
      LANGUAGE_ID,
      createOptiScriptLanguage(versionRef.current),
    );

    // Register completion provider
    const completionDisposable = monacoApi.languages.registerCompletionItemProvider(
      LANGUAGE_ID,
      createCompletionProvider(monacoApi, () => versionRef.current),
    );
    disposablesRef.current.push(completionDisposable);

    // Register hover provider
    const hoverDisposable = monacoApi.languages.registerHoverProvider(
      LANGUAGE_ID,
      createHoverProvider(monacoApi, () => versionRef.current),
    );
    disposablesRef.current.push(hoverDisposable);

    // Register signature help provider (parameter hints on '(' and ',')
    const signatureDisposable = monacoApi.languages.registerSignatureHelpProvider(
      LANGUAGE_ID,
      createSignatureHelpProvider(monacoApi, () => versionRef.current),
    );
    disposablesRef.current.push(signatureDisposable);

    // Register document symbol provider (outline / breadcrumbs)
    const symbolDisposable = monacoApi.languages.registerDocumentSymbolProvider(
      LANGUAGE_ID,
      createDocumentSymbolProvider(monacoApi),
    );
    disposablesRef.current.push(symbolDisposable);

    // Listen for content changes
    const changeDisposable = editor.onDidChangeModelContent(() => {
      const newValue = editor.getValue();
      onChange(newValue);

      // Detect version from annotation
      if (versionOverride === undefined) {
        const detected = detectVersion(newValue);
        if (detected !== versionRef.current) {
          versionRef.current = detected;
          setCurrentVersion(detected);
          onVersionChange?.(detected);

          // Re-register tokenizer for new version
          monacoApi.languages.setMonarchTokensProvider(
            LANGUAGE_ID,
            createOptiScriptLanguage(detected),
          );
        }
      }
    });
    disposablesRef.current.push(changeDisposable);

    // Glyph margin click handler for breakpoints
    const mouseDownDisposable = editor.onMouseDown((e) => {
      if (
        e.target.type === monacoApi.editor.MouseTargetType.GUTTER_GLYPH_MARGIN &&
        e.target.position
      ) {
        onBreakpointToggle?.(e.target.position.lineNumber);
      }
    });
    disposablesRef.current.push(mouseDownDisposable);

    return () => {
      for (const d of disposablesRef.current) {
        d.dispose();
      }
      disposablesRef.current = [];
      editor.dispose();
      editorRef.current = null;
    };
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  // Update theme
  useEffect(() => {
    if (editorRef.current) {
      monacoApi.editor.setTheme(monacoTheme);
    }
  }, [monacoTheme]);

  // Update readOnly
  useEffect(() => {
    if (editorRef.current) {
      editorRef.current.updateOptions({ readOnly });
    }
  }, [readOnly]);

  // Update value from outside (only if different from current)
  useEffect(() => {
    const editor = editorRef.current;
    if (editor && editor.getValue() !== value) {
      const model = editor.getModel();
      if (model) {
        model.setValue(value);
      }
    }
  }, [value]);

  // Update diagnostics as Monaco markers
  useEffect(() => {
    const editor = editorRef.current;
    if (!editor) return;

    const model = editor.getModel();
    if (!model) return;

    if (!diagnostics || diagnostics.length === 0) {
      monacoApi.editor.setModelMarkers(model, 'optiscript', []);
      return;
    }

    const markers: monacoApi.editor.IMarkerData[] = diagnostics.map((diag) => ({
      severity: mapSeverity(diag.severity),
      message: diag.message,
      startLineNumber: diag.startLine,
      startColumn: diag.startColumn,
      endLineNumber: diag.endLine,
      endColumn: diag.endColumn,
      source: 'OptiScript',
      code: diag.code,
    }));

    monacoApi.editor.setModelMarkers(model, 'optiscript', markers);
  }, [diagnostics]);

  // Update breakpoint glyph decorations when breakpointLines changes
  useEffect(() => {
    const editor = editorRef.current;
    if (!editor) return;

    const lines = breakpointLines ?? [];
    breakpointDecorationsRef.current = editor.deltaDecorations(
      breakpointDecorationsRef.current,
      lines.map((ln) => ({
        range: new monacoApi.Range(ln, 1, ln, 1),
        options: {
          isWholeLine: false,
          glyphMarginClassName: 'optiscript-breakpoint-glyph',
          stickiness: monacoApi.editor.TrackedRangeStickiness.NeverGrowsWhenTypingAtEdges,
        },
      })),
    );
  }, [breakpointLines]);

  // Update current debug line highlight
  useEffect(() => {
    const editor = editorRef.current;
    if (!editor) return;

    currentLineDecorationRef.current = editor.deltaDecorations(
      currentLineDecorationRef.current,
      currentDebugLine != null
        ? [{
            range: new monacoApi.Range(currentDebugLine, 1, currentDebugLine, 1),
            options: {
              isWholeLine: true,
              className: 'optiscript-current-line-highlight',
              stickiness: monacoApi.editor.TrackedRangeStickiness.NeverGrowsWhenTypingAtEdges,
            },
          }]
        : [],
    );

    // Reveal the current debug line in the editor viewport
    if (currentDebugLine != null) {
      editor.revealLineInCenter(currentDebugLine);
    }
  }, [currentDebugLine]);

  // Update inline debug value decorations
  useEffect(() => {
    const editor = editorRef.current;
    if (!editor) return;

    const values = inlineDebugValues ?? [];
    inlineValueDecorationsRef.current = editor.deltaDecorations(
      inlineValueDecorationsRef.current,
      values.map(({ line, text }) => ({
        range: new monacoApi.Range(line, 1, line, 1),
        options: {
          after: {
            content: `  ${text}`,
            inlineClassName: 'optiscript-inline-debug-value',
          },
          stickiness: monacoApi.editor.TrackedRangeStickiness.NeverGrowsWhenTypingAtEdges,
        },
      })),
    );
  }, [inlineDebugValues]);

  const handleVersionChange = useCallback(
    (event: React.ChangeEvent<HTMLSelectElement>) => {
      const v = parseInt(event.target.value, 10) as OptiVersion;
      versionRef.current = v;
      setCurrentVersion(v);
      onVersionChange?.(v);

      monacoApi.languages.setMonarchTokensProvider(
        LANGUAGE_ID,
        createOptiScriptLanguage(v),
      );
    },
    [onVersionChange],
  );

  const hasErrors = diagnostics?.some((d) => d.severity === 'error') ?? false;
  const hasDiagnostics = diagnostics !== undefined && diagnostics.length > 0;

  return (
    <div className={styles.container} role="region" aria-label="OptiScript Editor">
      <div className={styles.toolbar} role="toolbar" aria-label="Editor toolbar">
        <span className={styles.toolbarLabel} id="version-label">
          Version
        </span>
        <select
          className={styles.versionSelect}
          value={currentVersion}
          onChange={handleVersionChange}
          aria-labelledby="version-label"
        >
          <option value={2}>v2</option>
          <option value={3}>v3</option>
          <option value={4}>v4</option>
          <option value={5}>v5</option>
          <option value={6}>v6</option>
        </select>

        <div className={styles.statusIndicator} aria-live="polite">
          <span
            className={`${styles.statusDot} ${
              hasErrors
                ? styles.statusDotError
                : hasDiagnostics
                  ? styles.statusDotPending
                  : styles.statusDotOk
            }`}
            aria-hidden="true"
          />
          <span>
            {hasErrors
              ? `${diagnostics?.filter((d) => d.severity === 'error').length} error(s)`
              : hasDiagnostics
                ? `${diagnostics?.length} warning(s)`
                : 'Ready'}
          </span>
        </div>
      </div>
      <div
        ref={containerRef}
        className={styles.editorWrapper}
        role="region"
        aria-label="OptiScript source code"
      />
    </div>
  );
});

function mapSeverity(severity: string): monacoApi.MarkerSeverity {
  switch (severity) {
    case 'error': return monacoApi.MarkerSeverity.Error;
    case 'warning': return monacoApi.MarkerSeverity.Warning;
    case 'info': return monacoApi.MarkerSeverity.Info;
    case 'hint': return monacoApi.MarkerSeverity.Hint;
    default: return monacoApi.MarkerSeverity.Info;
  }
}
