/**
 * ImportWizard — Paste TradingView script, compile, view compatibility report.
 *
 * Modal dialog with focus trap. Steps: Paste -> Analyze -> Import.
 */
import { useState, useCallback } from 'react';
import { useFocusTrap } from '../../hooks';
import { detectVersion } from '../../languages';
import type { ImportAnalysis, OptiVersion, CompatibilityItem, Diagnostic } from '../../types';
import styles from './ImportWizard.module.css';

interface ImportWizardProps {
  /** Whether the wizard is open */
  open: boolean;
  /** Called when user closes the wizard */
  onClose: () => void;
  /** Called when user imports the script */
  onImport: (source: string, version: OptiVersion) => void;
}

/**
 * Performs a local compatibility analysis of pasted OptiScript source.
 * In production, this would call the Rust compiler via Tauri invoke.
 * Here we do a lightweight static analysis.
 */
function analyzeScript(source: string): ImportAnalysis {
  const version = detectVersion(source);

  const compatibility: CompatibilityItem[] = [];
  const suggestions: string[] = [];
  const diagnostics: Diagnostic[] = [];

  // Check for version annotation
  const hasVersionAnnotation = /\/\/@version=\d+/.test(source);
  compatibility.push({
    feature: 'Version annotation',
    supported: hasVersionAnnotation,
    notes: hasVersionAnnotation
      ? `Detected v${version}`
      : 'No //@version annotation found; defaulting to v5',
  });
  if (!hasVersionAnnotation) {
    suggestions.push('Add //@version=5 at the top of your script for explicit versioning.');
  }

  // Check for script declaration
  const hasIndicator = /\bindicator\s*\(/.test(source) || /\bstudy\s*\(/.test(source);
  const hasStrategy = /\bstrategy\s*\(/.test(source);
  const hasLibrary = /\blibrary\s*\(/.test(source);
  const scriptType = hasStrategy ? 'strategy' as const : hasLibrary ? 'library' as const : hasIndicator ? 'indicator' as const : null;

  compatibility.push({
    feature: 'Script declaration',
    supported: scriptType !== null,
    notes: scriptType
      ? `Detected ${scriptType} script`
      : 'No indicator(), strategy(), or library() declaration found',
  });

  // Check for common built-in usage
  const usesTA = /\bta\./.test(source) || /\bsma\b|\bema\b|\brsi\b|\bmacd\b/.test(source);
  compatibility.push({
    feature: 'Technical analysis functions',
    supported: true,
    notes: usesTA ? 'TA functions detected and supported' : 'No TA functions detected',
  });

  // Check for plot functions
  const usesPlot = /\bplot\s*\(/.test(source) || /\bplotshape\s*\(/.test(source);
  compatibility.push({
    feature: 'Plot functions',
    supported: true,
    notes: usesPlot ? 'Plot calls detected and supported' : 'No plot calls detected',
  });

  // Check for v5+ features
  const usesTypes = /\btype\s+\w+/.test(source);
  const usesMethods = /\bmethod\s+\w+/.test(source);
  const usesImport = /\bimport\s+\w+/.test(source);
  const usesMap = /\bmap\s*</.test(source) || /\bmap\./.test(source);
  const usesMatrix = /\bmatrix\s*</.test(source) || /\bmatrix\./.test(source);

  if (usesTypes) {
    compatibility.push({
      feature: 'User-defined types',
      supported: version >= 5,
      notes: version >= 5 ? 'UDTs are supported in v5+' : 'UDTs require v5 or later',
    });
  }

  if (usesMethods) {
    compatibility.push({
      feature: 'Methods',
      supported: version >= 5,
      notes: version >= 5 ? 'Methods are supported in v5+' : 'Methods require v5 or later',
    });
  }

  if (usesImport) {
    compatibility.push({
      feature: 'Library imports',
      supported: version >= 5,
      notes: 'Library import resolution uses local .optilib storage',
    });
  }

  if (usesMap) {
    compatibility.push({
      feature: 'Map data structure',
      supported: version >= 5,
      notes: version >= 5 ? 'Maps are supported' : 'Maps require v5 or later',
    });
  }

  if (usesMatrix) {
    compatibility.push({
      feature: 'Matrix data structure',
      supported: version >= 5,
      notes: version >= 5 ? 'Matrices are supported' : 'Matrices require v5 or later',
    });
  }

  // Check for request.security
  const usesSecurity = /\brequest\.security\b/.test(source) || /\bsecurity\s*\(/.test(source);
  if (usesSecurity) {
    compatibility.push({
      feature: 'Multi-timeframe data (request.security)',
      supported: true,
      notes: 'Multi-timeframe requests are supported with lookahead protection',
    });
  }

  // Check for drawings
  const usesDrawings = /\bline\.new\b/.test(source) || /\blabel\.new\b/.test(source) || /\bbox\.new\b/.test(source);
  if (usesDrawings) {
    compatibility.push({
      feature: 'Drawing objects',
      supported: version >= 4,
      notes: version >= 4 ? 'Drawing objects are supported' : 'Drawing objects require v4 or later',
    });
  }

  // Check for tables
  const usesTables = /\btable\.new\b/.test(source);
  if (usesTables) {
    compatibility.push({
      feature: 'Table objects',
      supported: version >= 5,
      notes: version >= 5 ? 'Tables are supported' : 'Tables require v5 or later',
    });
  }

  // Check for alerts
  const usesAlert = /\balert\s*\(/.test(source) || /\balertcondition\s*\(/.test(source);
  if (usesAlert) {
    compatibility.push({
      feature: 'Alerts',
      supported: true,
      notes: 'Alert events are routed through DeskModal notifications',
    });
  }

  // Generate error-level diagnostics for obvious issues
  if (!scriptType && source.trim().length > 0) {
    diagnostics.push({
      severity: 'warning',
      message: 'No script declaration found. Add indicator() or strategy() call.',
      startLine: 1,
      startColumn: 1,
      endLine: 1,
      endColumn: 1,
      code: 'W001',
    });
  }

  const allSupported = compatibility.every((c) => c.supported);
  if (!allSupported) {
    const unsupported = compatibility.filter((c) => !c.supported);
    for (const item of unsupported) {
      suggestions.push(`${item.feature}: ${item.notes}`);
    }
  }

  return {
    detectedVersion: version,
    scriptType,
    compilationResult: {
      success: diagnostics.filter((d) => d.severity === 'error').length === 0,
      diagnostics,
      version,
      scriptType,
      compilationTimeMs: 0,
    },
    compatibility,
    suggestions,
  };
}

export function ImportWizard({ open, onClose, onImport }: ImportWizardProps) {
  const [source, setSource] = useState('');
  const [analysis, setAnalysis] = useState<ImportAnalysis | null>(null);

  const containerRef = useFocusTrap<HTMLDivElement>({
    active: open,
    onEscape: onClose,
  });

  const handleAnalyze = useCallback(() => {
    if (source.trim().length === 0) return;
    const result = analyzeScript(source);
    setAnalysis(result);
  }, [source]);

  const handleImport = useCallback(() => {
    if (!analysis) return;
    onImport(source, analysis.detectedVersion);
    setSource('');
    setAnalysis(null);
    onClose();
  }, [source, analysis, onImport, onClose]);

  const handleClose = useCallback(() => {
    setSource('');
    setAnalysis(null);
    onClose();
  }, [onClose]);

  if (!open) return null;

  const hasErrors = analysis?.compilationResult.diagnostics.some(
    (d) => d.severity === 'error',
  ) ?? false;

  return (
    <div
      className={styles.overlay}
      role="dialog"
      aria-modal="true"
      aria-label="Import TradingView Script"
    >
      <div className={styles.dialog} ref={containerRef}>
        <div className={styles.header}>
          <span className={styles.headerTitle}>Import TradingView Script</span>
          <button
            className={styles.closeButton}
            onClick={handleClose}
            aria-label="Close import wizard"
            type="button"
          >
            {'\u2715'}
          </button>
        </div>

        <div className={styles.body}>
          {/* Paste section */}
          <div className={styles.pasteSection}>
            <label className={styles.sectionLabel} htmlFor="import-paste-area">
              Paste your OptiScript source code
            </label>
            <textarea
              id="import-paste-area"
              className={styles.pasteArea}
              value={source}
              onChange={(e) => {
                setSource(e.target.value);
                setAnalysis(null);
              }}
              placeholder={`//@version=5
indicator("My Indicator", overlay=true)
fast = ta.sma(close, 9)
slow = ta.sma(close, 21)
plot(fast, color=color.green)
plot(slow, color=color.red)`}
              spellCheck={false}
              aria-label="OptiScript source code input"
            />
          </div>

          {/* Analysis results */}
          {analysis && (
            <div className={styles.analysisSection}>
              <div className={styles.detectedInfo}>
                <span className={styles.infoBadge}>v{analysis.detectedVersion}</span>
                {analysis.scriptType && (
                  <span className={styles.infoBadge}>{analysis.scriptType}</span>
                )}
                <span className={styles.infoText}>
                  {analysis.compilationResult.success
                    ? 'Script is compatible'
                    : 'Script has issues'}
                </span>
              </div>

              {/* Compatibility checklist */}
              <div>
                <div className={styles.sectionLabel}>Compatibility Check</div>
                <ul className={styles.compatList} role="list" aria-label="Compatibility results">
                  {analysis.compatibility.map((item, i) => (
                    <li key={i} className={styles.compatItem}>
                      <span
                        className={`${styles.compatIcon} ${
                          item.supported ? styles.compatSupported : styles.compatUnsupported
                        }`}
                        aria-hidden="true"
                      >
                        {item.supported ? '\u2713' : '\u2717'}
                      </span>
                      <div>
                        <span className={styles.compatFeature}>{item.feature}</span>
                        <div className={styles.compatNotes}>{item.notes}</div>
                      </div>
                    </li>
                  ))}
                </ul>
              </div>

              {/* Compilation errors */}
              {analysis.compilationResult.diagnostics.length > 0 && (
                <div className={styles.errorSection}>
                  <div className={styles.errorTitle}>Compilation Issues</div>
                  <ul className={styles.errorList} role="list">
                    {analysis.compilationResult.diagnostics.map((diag, i) => (
                      <li key={i} className={styles.errorItem}>
                        Ln {diag.startLine}: {diag.message}
                      </li>
                    ))}
                  </ul>
                </div>
              )}

              {/* Suggestions */}
              {analysis.suggestions.length > 0 && (
                <div className={styles.suggestionsSection}>
                  <div className={styles.suggestionsTitle}>Suggestions</div>
                  <ul className={styles.suggestionsList} role="list">
                    {analysis.suggestions.map((s, i) => (
                      <li key={i} className={styles.suggestionItem}>
                        {s}
                      </li>
                    ))}
                  </ul>
                </div>
              )}
            </div>
          )}
        </div>

        <div className={styles.footer}>
          {analysis && (
            <span className={styles.compileStatus}>
              Compilation: {analysis.compilationResult.success ? 'OK' : 'Failed'}
            </span>
          )}
          <button
            className={styles.secondaryButton}
            onClick={handleClose}
            type="button"
          >
            Cancel
          </button>
          {!analysis ? (
            <button
              className={styles.primaryButton}
              onClick={handleAnalyze}
              disabled={source.trim().length === 0}
              type="button"
            >
              Analyze
            </button>
          ) : (
            <button
              className={styles.primaryButton}
              onClick={handleImport}
              disabled={hasErrors}
              type="button"
            >
              Import to Editor
            </button>
          )}
        </div>
      </div>
    </div>
  );
}
