/**
 * OptiScript Signature Help Provider for Monaco Editor
 *
 * Provides parameter hints when typing function calls.
 * Triggered on '(' and ',' characters, showing the current parameter
 * documentation for built-in and namespaced functions.
 */
import type * as monaco from 'monaco-editor';
import type { OptiVersion } from '../types';
import { BUILTIN_FUNCTIONS } from './completions';

/** Parsed function call context at the cursor position */
interface CallContext {
  readonly functionName: string;
  readonly namespace: string | undefined;
  readonly activeParameter: number;
}

/**
 * Parses the line text up to the cursor to determine which function is being
 * called and which parameter the cursor is on. Handles nested parentheses.
 */
function parseCallContext(lineText: string, column: number): CallContext | null {
  const textUpToCursor = lineText.substring(0, column - 1);

  // Walk backwards through the text to find the matching open paren,
  // accounting for nested parens and string literals.
  let depth = 0;
  let commaCount = 0;
  let inString = false;
  let stringChar = '';
  let openParenIndex = -1;

  for (let i = textUpToCursor.length - 1; i >= 0; i--) {
    const ch = textUpToCursor[i];

    // Handle string boundaries (walk backwards: a quote either closes or opens)
    if ((ch === '"' || ch === "'") && (i === 0 || textUpToCursor[i - 1] !== '\\')) {
      if (inString && ch === stringChar) {
        inString = false;
        continue;
      } else if (!inString) {
        inString = true;
        stringChar = ch;
        continue;
      }
    }

    if (inString) continue;

    if (ch === ')') {
      depth++;
    } else if (ch === '(') {
      if (depth === 0) {
        openParenIndex = i;
        break;
      }
      depth--;
    } else if (ch === ',' && depth === 0) {
      commaCount++;
    }
  }

  if (openParenIndex < 0) return null;

  // Extract the function name before the open paren
  const beforeParen = textUpToCursor.substring(0, openParenIndex).trimEnd();
  const identMatch = beforeParen.match(/(\w+)(?:\.(\w+))?\s*$/);
  if (!identMatch) return null;

  let namespace: string | undefined;
  let functionName: string;

  if (identMatch[2]) {
    // namespace.function pattern
    namespace = identMatch[1];
    functionName = identMatch[2];
  } else {
    functionName = identMatch[1];
  }

  return {
    functionName,
    namespace,
    activeParameter: commaCount,
  };
}

/**
 * Extracts parameter names from a function detail string like
 * "ta.sma(source, length) -> series float".
 */
function extractParameters(detail: string): string[] {
  const parenMatch = detail.match(/\(([^)]*)\)/);
  if (!parenMatch) return [];

  const paramStr = parenMatch[1].trim();
  if (paramStr.length === 0) return [];

  return paramStr.split(',').map((p) => p.trim()).filter((p) => p.length > 0);
}

/**
 * Creates a Monaco SignatureHelpProvider for OptiScript.
 */
export function createSignatureHelpProvider(
  _monacoApi: typeof monaco,
  getVersion: () => OptiVersion,
): monaco.languages.SignatureHelpProvider {
  return {
    signatureHelpTriggerCharacters: ['(', ','],

    provideSignatureHelp(
      model: monaco.editor.ITextModel,
      position: monaco.Position,
    ): monaco.languages.ProviderResult<monaco.languages.SignatureHelpResult> {
      const version = getVersion();
      const lineContent = model.getLineContent(position.lineNumber);
      const ctx = parseCallContext(lineContent, position.column);
      if (!ctx) return null;

      // Find the matching built-in function
      const fn = BUILTIN_FUNCTIONS.find(
        (f) =>
          f.label === ctx.functionName &&
          f.namespace === ctx.namespace &&
          f.minVersion <= version,
      );
      if (!fn) return null;

      const parameters = extractParameters(fn.detail);
      if (parameters.length === 0) return null;

      const parameterInfos: monaco.languages.ParameterInformation[] = parameters.map(
        (param) => ({
          label: param,
          documentation: `Parameter: \`${param}\``,
        }),
      );

      const qualifiedName = fn.namespace ? `${fn.namespace}.${fn.label}` : fn.label;
      const signature: monaco.languages.SignatureInformation = {
        label: fn.detail,
        documentation: { value: `**${qualifiedName}**\n\n${fn.documentation}` },
        parameters: parameterInfos,
      };

      return {
        value: {
          signatures: [signature],
          activeSignature: 0,
          activeParameter: Math.min(ctx.activeParameter, parameters.length - 1),
        },
        dispose() { /* no-op */ },
      };
    },
  };
}
