/**
 * PositionPanel — Displays current strategy position state.
 *
 * Shows side (LONG/SHORT/FLAT), quantity, average entry price,
 * unrealized P&L, realized P&L, and equity. P&L values are
 * color-coded green for positive and red for negative.
 */
import type { PositionInfo } from '../../types/debug';
import styles from './PositionPanel.module.css';

interface PositionPanelProps {
  /** Current position info, or null if no position data available */
  readonly position: PositionInfo | null;
}

/** Display label for the side */
const SIDE_LABELS: Record<PositionInfo['side'], string> = {
  long: 'LONG',
  short: 'SHORT',
  flat: 'FLAT',
};

/** Map side to CSS class */
function sideClass(side: PositionInfo['side']): string {
  switch (side) {
    case 'long':  return styles.sideLong;
    case 'short': return styles.sideShort;
    case 'flat':  return styles.sideFlat;
  }
}

/** Format a number for display */
function formatNumber(value: number, decimals = 2): string {
  return value.toFixed(decimals);
}

/** Get the P&L color class */
function pnlClass(value: number): string {
  if (value > 0) return styles.pnlPositive;
  if (value < 0) return styles.pnlNegative;
  return styles.pnlZero;
}

/** Format P&L with sign */
function formatPnl(value: number): string {
  const sign = value > 0 ? '+' : '';
  return `${sign}${value.toFixed(2)}`;
}

export function PositionPanel({ position }: PositionPanelProps) {
  return (
    <div className={styles.panel} role="region" aria-label="Position">
      <div className={styles.header}>
        <span className={styles.headerTitle}>Position</span>
        {position && (
          <span
            className={`${styles.sideBadge} ${sideClass(position.side)}`}
            role="status"
            aria-label={`Side: ${SIDE_LABELS[position.side]}`}
          >
            {SIDE_LABELS[position.side]}
          </span>
        )}
      </div>

      {position === null ? (
        <div className={styles.empty} role="status">
          No position data
        </div>
      ) : (
        <dl className={styles.grid} aria-label="Position details">
          <div className={styles.row} tabIndex={-1}>
            <dt className={styles.label}>Quantity</dt>
            <dd className={styles.value}>{formatNumber(position.qty, 0)}</dd>
          </div>

          <div className={styles.row} tabIndex={-1}>
            <dt className={styles.label}>Avg Entry</dt>
            <dd className={styles.value}>{formatNumber(position.avgEntry)}</dd>
          </div>

          <div className={styles.divider} aria-hidden="true" />

          <div className={styles.row} tabIndex={-1}>
            <dt className={styles.label}>Unrealized P&amp;L</dt>
            <dd className={`${styles.value} ${pnlClass(position.unrealizedPnl)}`}>
              {formatPnl(position.unrealizedPnl)}
            </dd>
          </div>

          <div className={styles.row} tabIndex={-1}>
            <dt className={styles.label}>Realized P&amp;L</dt>
            <dd className={`${styles.value} ${pnlClass(position.realizedPnl)}`}>
              {formatPnl(position.realizedPnl)}
            </dd>
          </div>

          <div className={styles.divider} aria-hidden="true" />

          <div className={styles.row} tabIndex={-1}>
            <dt className={styles.label}>Equity</dt>
            <dd className={`${styles.value} ${styles.valueEquity}`}>
              {formatNumber(position.equity)}
            </dd>
          </div>
        </dl>
      )}
    </div>
  );
}
