/**
 * VariablesPanel — Debug variable tree + watch expressions.
 *
 * Displays all debug variables grouped by category (User, Built-in,
 * BarState, Series, Strategy) in an accessible tree view, plus a
 * watch expressions list with add/remove.
 */
import { useCallback, useEffect, useMemo, useRef, useState } from 'react';
import type { DebugVariable, VariableCategory, WatchExpression, IndicatorStateInfo } from '../../types/debug';
import styles from './VariablesPanel.module.css';

interface VariablesPanelProps {
  /** All debug variables from the current execution state */
  variables: readonly DebugVariable[];
  /** Persistent indicator states (TA function call sites) */
  indicatorStates?: readonly IndicatorStateInfo[];
  /** User-defined watch expressions */
  watches: readonly WatchExpression[];
  /** Add a new watch expression */
  onAddWatch: (expr: string) => void;
  /** Remove a watch expression by id */
  onRemoveWatch: (id: string) => void;
  /** Override a variable's value at runtime (requires backend support) */
  onSetVariable?: (name: string, value: string) => void;
}

/** Display labels for each variable category */
const CATEGORY_LABELS: Record<VariableCategory, string> = {
  user: 'User',
  builtin: 'Built-in',
  barstate: 'BarState',
  series: 'Series',
  strategy: 'Strategy',
};

/** Ordered categories for consistent rendering */
const CATEGORY_ORDER: readonly VariableCategory[] = [
  'user',
  'builtin',
  'barstate',
  'series',
  'strategy',
];

/** Map a type string to its badge CSS class */
function typeBadgeClass(type: string): string {
  switch (type.toLowerCase()) {
    case 'float':
      return styles.typeBadgeFloat;
    case 'int':
      return styles.typeBadgeInt;
    case 'bool':
      return styles.typeBadgeBool;
    case 'string':
      return styles.typeBadgeString;
    case 'na':
      return styles.typeBadgeNa;
    default:
      return styles.typeBadgeNa;
  }
}

/** Group variables by their category */
function groupByCategory(
  variables: readonly DebugVariable[],
): Map<VariableCategory, DebugVariable[]> {
  const groups = new Map<VariableCategory, DebugVariable[]>();
  for (const variable of variables) {
    const existing = groups.get(variable.category);
    if (existing) {
      existing.push(variable);
    } else {
      groups.set(variable.category, [variable]);
    }
  }
  return groups;
}

/** Render a single variable row with optional inline editing */
function VariableRow({
  variable,
  depth = 0,
  onSetVariable,
}: {
  variable: DebugVariable;
  depth?: number;
  onSetVariable?: (name: string, value: string) => void;
}) {
  const [expanded, setExpanded] = useState(false);
  const [editing, setEditing] = useState(false);
  const [editValue, setEditValue] = useState('');
  const editInputRef = useRef<HTMLInputElement>(null);
  const hasChildren = variable.children && variable.children.length > 0;

  const handleKeyDown = (event: React.KeyboardEvent) => {
    if (editing) return;
    if (hasChildren) {
      if (event.key === 'ArrowRight' && !expanded) {
        event.preventDefault();
        setExpanded(true);
      } else if (event.key === 'ArrowLeft' && expanded) {
        event.preventDefault();
        setExpanded(false);
      } else if (event.key === 'Enter' || event.key === ' ') {
        event.preventDefault();
        setExpanded((prev) => !prev);
      }
    }
  };

  const startEditing = () => {
    if (!onSetVariable) return;
    setEditValue(variable.value);
    setEditing(true);
  };

  const commitEdit = () => {
    if (onSetVariable && editValue !== variable.value) {
      onSetVariable(variable.name, editValue);
    }
    setEditing(false);
  };

  const cancelEdit = () => {
    setEditing(false);
  };

  const handleEditKeyDown = (event: React.KeyboardEvent<HTMLInputElement>) => {
    if (event.key === 'Enter') {
      event.preventDefault();
      commitEdit();
    } else if (event.key === 'Escape') {
      event.preventDefault();
      cancelEdit();
    }
  };

  // Auto-focus the edit input when entering edit mode
  useEffect(() => {
    if (editing && editInputRef.current) {
      editInputRef.current.focus();
      editInputRef.current.select();
    }
  }, [editing]);

  return (
    <>
      <li
        className={styles.variable}
        role="treeitem"
        aria-expanded={hasChildren ? expanded : undefined}
        aria-level={depth + 2}
        tabIndex={0}
        onKeyDown={handleKeyDown}
        onClick={hasChildren ? () => setExpanded((prev) => !prev) : undefined}
      >
        {hasChildren && (
          <span
            className={`${styles.chevron} ${expanded ? styles.chevronExpanded : ''}`}
            aria-hidden="true"
          >
            {'\u25B6'}
          </span>
        )}
        <span className={styles.variableName}>{variable.name}</span>
        <span className={`${styles.typeBadge} ${typeBadgeClass(variable.type)}`}>
          {variable.type}
        </span>
        {editing ? (
          <input
            ref={editInputRef}
            className={styles.variableEditInput}
            type="text"
            value={editValue}
            onChange={(e) => setEditValue(e.target.value)}
            onKeyDown={handleEditKeyDown}
            onBlur={cancelEdit}
            aria-label={`Edit variable ${variable.name}`}
          />
        ) : (
          <span
            className={`${styles.variableValue} ${variable.isNa ? styles.variableValueNa : ''} ${onSetVariable ? styles.variableValueEditable : ''}`}
            onDoubleClick={startEditing}
          >
            {variable.value}
          </span>
        )}
      </li>
      {hasChildren && expanded && (
        <ul className={styles.childrenList} role="group">
          {variable.children!.map((child) => (
            <VariableRow
              key={child.name}
              variable={child}
              depth={depth + 1}
              onSetVariable={onSetVariable}
            />
          ))}
        </ul>
      )}
    </>
  );
}

/** Render a category group with expandable header */
function CategoryGroup({
  category,
  variables,
  onSetVariable,
}: {
  category: VariableCategory;
  variables: DebugVariable[];
  onSetVariable?: (name: string, value: string) => void;
}) {
  const [expanded, setExpanded] = useState(true);

  const handleKeyDown = (event: React.KeyboardEvent) => {
    if (event.key === 'ArrowRight' && !expanded) {
      event.preventDefault();
      setExpanded(true);
    } else if (event.key === 'ArrowLeft' && expanded) {
      event.preventDefault();
      setExpanded(false);
    } else if (event.key === 'Enter' || event.key === ' ') {
      event.preventDefault();
      setExpanded((prev) => !prev);
    }
  };

  return (
    <li className={styles.group} role="treeitem" aria-expanded={expanded}>
      <button
        className={styles.groupHeader}
        onClick={() => setExpanded((prev) => !prev)}
        onKeyDown={handleKeyDown}
        aria-label={`${CATEGORY_LABELS[category]} variables, ${variables.length} items`}
        type="button"
      >
        <span
          className={`${styles.chevron} ${expanded ? styles.chevronExpanded : ''}`}
          aria-hidden="true"
        >
          {'\u25B6'}
        </span>
        {CATEGORY_LABELS[category]}
        <span className={styles.groupCount}>{variables.length}</span>
      </button>
      {expanded && (
        <ul className={styles.groupItems} role="group">
          {variables.map((variable) => (
            <VariableRow key={variable.name} variable={variable} onSetVariable={onSetVariable} />
          ))}
        </ul>
      )}
    </li>
  );
}

export function VariablesPanel({
  variables,
  indicatorStates,
  watches,
  onAddWatch,
  onRemoveWatch,
  onSetVariable,
}: VariablesPanelProps) {
  const [watchInput, setWatchInput] = useState('');
  const watchInputRef = useRef<HTMLInputElement>(null);

  const grouped = useMemo(() => groupByCategory(variables), [variables]);

  /** Categories that have at least one variable, in display order */
  const activeCategories = useMemo(
    () => CATEGORY_ORDER.filter((cat) => grouped.has(cat)),
    [grouped],
  );

  const handleWatchSubmit = useCallback(
    (event: React.KeyboardEvent<HTMLInputElement>) => {
      if (event.key === 'Enter') {
        const expression = watchInput.trim();
        if (expression.length > 0) {
          onAddWatch(expression);
          setWatchInput('');
        }
      }
    },
    [watchInput, onAddWatch],
  );

  const handleWatchInputChange = useCallback(
    (event: React.ChangeEvent<HTMLInputElement>) => {
      setWatchInput(event.target.value);
    },
    [],
  );

  return (
    <div className={styles.panel} role="region" aria-label="Variables and watches">
      {/* Variables tree */}
      <div className={styles.header}>
        <span className={styles.headerTitle}>Variables</span>
      </div>
      <div className={styles.content}>
        {activeCategories.length === 0 ? (
          <div className={styles.empty} role="status">
            No variables
          </div>
        ) : (
          <ul role="tree" aria-label="Debug variables">
            {activeCategories.map((category) => (
              <CategoryGroup
                key={category}
                category={category}
                variables={grouped.get(category)!}
                onSetVariable={onSetVariable}
              />
            ))}
          </ul>
        )}
      </div>

      {/* Indicator States */}
      {indicatorStates && indicatorStates.length > 0 && (
        <div className={styles.indicatorSection}>
          <div className={styles.header}>
            <span className={styles.headerTitle}>Indicators</span>
            <span className={styles.groupCount}>{indicatorStates.length}</span>
          </div>
          <ul className={styles.indicatorList} role="list" aria-label="Indicator states">
            {indicatorStates.map((state) => (
              <li
                key={state.callSiteId}
                className={styles.indicatorItem}
                tabIndex={0}
                aria-label={`Indicator call_site_${state.callSiteId}: ${state.description}`}
              >
                <span className={styles.indicatorCallSite}>
                  call_site_{state.callSiteId}
                </span>
                <span className={styles.indicatorDescription}>
                  {state.description}
                </span>
              </li>
            ))}
          </ul>
        </div>
      )}

      {/* Watch Expressions */}
      <div className={styles.watchSection}>
        <div className={styles.header}>
          <span className={styles.headerTitle}>Watch Expressions</span>
        </div>

        {watches.length > 0 && (
          <ul className={styles.watchList} role="list" aria-label="Watch expressions">
            {watches.map((watch) => (
              <li
                key={watch.id}
                className={styles.watchItem}
                tabIndex={0}
                aria-label={`Watch: ${watch.expression} = ${watch.error ?? watch.value}`}
              >
                <span className={styles.watchExpression}>{watch.expression}</span>
                <span
                  className={`${styles.watchValue} ${watch.error ? styles.watchError : ''}`}
                >
                  {watch.error ?? watch.value}
                </span>
                <button
                  className={styles.watchRemoveButton}
                  onClick={() => onRemoveWatch(watch.id)}
                  aria-label={`Remove watch: ${watch.expression}`}
                  type="button"
                >
                  {'\u2715'}
                </button>
              </li>
            ))}
          </ul>
        )}

        <div className={styles.watchInputRow}>
          <input
            ref={watchInputRef}
            className={styles.watchInput}
            type="text"
            placeholder="Add expression..."
            value={watchInput}
            onChange={handleWatchInputChange}
            onKeyDown={handleWatchSubmit}
            aria-label="Add watch expression"
          />
        </div>
      </div>
    </div>
  );
}
