/**
 * EquityCurveNavigator — Simple SVG equity curve with click-to-navigate.
 *
 * Renders a line chart of the equity curve. Clicking on the chart
 * jumps to the corresponding bar. The current bar is highlighted
 * with a vertical marker line. Responsively fills container width.
 */
import { useCallback, useMemo, useRef } from 'react';
import styles from './EquityCurveNavigator.module.css';

interface EquityCurveNavigatorProps {
  /** Equity value at each bar index */
  readonly equityCurve: readonly number[];
  /** Currently selected bar index */
  readonly currentBar: number;
  /** Navigate to a specific bar */
  onBarClick: (bar: number) => void;
}

/** SVG viewBox dimensions */
const VIEW_WIDTH = 600;
const VIEW_HEIGHT = 120;
const PADDING_TOP = 10;
const PADDING_BOTTOM = 10;
const PADDING_LEFT = 4;
const PADDING_RIGHT = 4;

export function EquityCurveNavigator({
  equityCurve,
  currentBar,
  onBarClick,
}: EquityCurveNavigatorProps) {
  const svgRef = useRef<SVGSVGElement>(null);

  const { pathD, minVal, maxVal } = useMemo(() => {
    if (equityCurve.length === 0) {
      return { pathD: '', minVal: 0, maxVal: 0 };
    }

    let min = equityCurve[0];
    let max = equityCurve[0];
    for (const v of equityCurve) {
      if (v < min) min = v;
      if (v > max) max = v;
    }

    // Avoid zero-height range
    if (max === min) {
      max = min + 1;
    }

    const drawWidth = VIEW_WIDTH - PADDING_LEFT - PADDING_RIGHT;
    const drawHeight = VIEW_HEIGHT - PADDING_TOP - PADDING_BOTTOM;
    const totalBars = equityCurve.length;

    const points: string[] = [];
    for (let i = 0; i < totalBars; i++) {
      const x = PADDING_LEFT + (i / Math.max(1, totalBars - 1)) * drawWidth;
      const y = PADDING_TOP + (1 - (equityCurve[i] - min) / (max - min)) * drawHeight;
      points.push(`${i === 0 ? 'M' : 'L'}${x.toFixed(1)},${y.toFixed(1)}`);
    }

    return { pathD: points.join(' '), minVal: min, maxVal: max };
  }, [equityCurve]);

  /** Current bar X position */
  const currentBarX = useMemo(() => {
    if (equityCurve.length <= 1) return PADDING_LEFT;
    const drawWidth = VIEW_WIDTH - PADDING_LEFT - PADDING_RIGHT;
    return PADDING_LEFT + (currentBar / Math.max(1, equityCurve.length - 1)) * drawWidth;
  }, [equityCurve.length, currentBar]);

  /** Handle click on the SVG to navigate to a bar */
  const handleClick = useCallback(
    (event: React.MouseEvent<SVGSVGElement>) => {
      const svg = svgRef.current;
      if (!svg || equityCurve.length === 0) return;

      const rect = svg.getBoundingClientRect();
      const clickX = event.clientX - rect.left;
      const ratio = clickX / rect.width;
      const barIndex = Math.round(ratio * (equityCurve.length - 1));
      const clampedBar = Math.max(0, Math.min(equityCurve.length - 1, barIndex));
      onBarClick(clampedBar);
    },
    [equityCurve.length, onBarClick],
  );

  /** Handle keyboard navigation on the SVG */
  const handleKeyDown = useCallback(
    (event: React.KeyboardEvent<SVGSVGElement>) => {
      if (equityCurve.length === 0) return;

      if (event.key === 'ArrowRight') {
        event.preventDefault();
        const next = Math.min(equityCurve.length - 1, currentBar + 1);
        onBarClick(next);
      } else if (event.key === 'ArrowLeft') {
        event.preventDefault();
        const prev = Math.max(0, currentBar - 1);
        onBarClick(prev);
      } else if (event.key === 'Home') {
        event.preventDefault();
        onBarClick(0);
      } else if (event.key === 'End') {
        event.preventDefault();
        onBarClick(equityCurve.length - 1);
      }
    },
    [equityCurve.length, currentBar, onBarClick],
  );

  return (
    <div className={styles.panel} role="region" aria-label="Equity curve navigator">
      <div className={styles.header}>
        <span className={styles.headerTitle}>Equity Curve</span>
        <span className={styles.rangeLabel}>
          <span className={styles.rangeMin}>{minVal.toFixed(0)}</span>
          <span className={styles.rangeSep}>{'\u2013'}</span>
          <span className={styles.rangeMax}>{maxVal.toFixed(0)}</span>
        </span>
      </div>

      <div className={styles.chartContainer}>
        {equityCurve.length === 0 ? (
          <div className={styles.empty} role="status">
            No equity data
          </div>
        ) : (
          <svg
            ref={svgRef}
            className={styles.chart}
            viewBox={`0 0 ${VIEW_WIDTH} ${VIEW_HEIGHT}`}
            preserveAspectRatio="none"
            onClick={handleClick}
            onKeyDown={handleKeyDown}
            tabIndex={0}
            role="img"
            aria-label={`Equity curve chart, bar ${currentBar} of ${equityCurve.length}. Use arrow keys to navigate.`}
          >
            {/* Grid line at zero if visible */}
            {minVal < 0 && maxVal > 0 && (
              <line
                x1={PADDING_LEFT}
                x2={VIEW_WIDTH - PADDING_RIGHT}
                y1={PADDING_TOP + (1 - (0 - minVal) / (maxVal - minVal)) * (VIEW_HEIGHT - PADDING_TOP - PADDING_BOTTOM)}
                y2={PADDING_TOP + (1 - (0 - minVal) / (maxVal - minVal)) * (VIEW_HEIGHT - PADDING_TOP - PADDING_BOTTOM)}
                className={styles.zeroLine}
              />
            )}

            {/* Equity line */}
            <path
              d={pathD}
              className={styles.equityLine}
              fill="none"
            />

            {/* Current bar vertical marker */}
            <line
              x1={currentBarX}
              x2={currentBarX}
              y1={PADDING_TOP}
              y2={VIEW_HEIGHT - PADDING_BOTTOM}
              className={styles.currentBarLine}
            />

            {/* Current bar dot */}
            {equityCurve.length > 0 && currentBar >= 0 && currentBar < equityCurve.length && (
              <circle
                cx={currentBarX}
                cy={
                  PADDING_TOP +
                  (1 - (equityCurve[currentBar] - minVal) / (maxVal - minVal)) *
                    (VIEW_HEIGHT - PADDING_TOP - PADDING_BOTTOM)
                }
                r="3"
                className={styles.currentBarDot}
              />
            )}
          </svg>
        )}
      </div>
    </div>
  );
}
