/**
 * CallStackPanel -- displays the current call stack during a debug session.
 *
 * Frames are listed top-to-bottom with the most recent (top) frame first.
 * The top frame is highlighted with the accent color. Clicking a frame
 * emits `onFrameClick` so the editor can navigate to the source location.
 */
import type { CallFrame } from '../../types/debug';
import styles from './CallStackPanel.module.css';

interface CallStackPanelProps {
  /** Current call stack, ordered most-recent-first. */
  readonly callStack: readonly CallFrame[];
  /** Fired when the user clicks a frame to navigate to its source. */
  onFrameClick?: (frame: CallFrame) => void;
}

export function CallStackPanel({ callStack, onFrameClick }: CallStackPanelProps) {
  const handleFrameKeyDown = (event: React.KeyboardEvent, frame: CallFrame) => {
    if (event.key === 'Enter' || event.key === ' ') {
      event.preventDefault();
      onFrameClick?.(frame);
    }
  };

  return (
    <div
      className={styles.panel}
      role="region"
      aria-label="Call stack"
    >
      <div className={styles.header}>
        <span className={styles.headerTitle}>Call Stack</span>
        {callStack.length > 0 && (
          <span className={styles.frameCount} aria-label={`${callStack.length} frames`}>
            {callStack.length}
          </span>
        )}
      </div>

      {callStack.length === 0 ? (
        <div className={styles.empty} role="status">
          No call stack
        </div>
      ) : (
        <ul className={styles.list} role="list" aria-label="Call stack frames">
          {callStack.map((frame, index) => {
            const isTop = index === 0;
            const itemClasses = [
              styles.item,
              isTop ? styles.itemTop : undefined,
            ]
              .filter(Boolean)
              .join(' ');

            return (
              <li
                key={frame.id}
                className={itemClasses}
                role="listitem"
                tabIndex={0}
                onClick={() => onFrameClick?.(frame)}
                onKeyDown={(e) => handleFrameKeyDown(e, frame)}
                aria-label={`${frame.functionName} at line ${frame.line}, column ${frame.column}${isTop ? ' (current frame)' : ''}`}
                aria-current={isTop ? 'true' : undefined}
              >
                <span className={styles.frameIndex} aria-hidden="true">
                  {index}
                </span>
                <div className={styles.frameContent}>
                  <span className={isTop ? styles.functionNameTop : styles.functionName}>
                    {frame.functionName}
                  </span>
                  <span className={styles.sourceLocation}>
                    {frame.source ? `${frame.source}:` : ''}
                    {frame.line}:{frame.column}
                  </span>
                </div>
              </li>
            );
          })}
        </ul>
      )}
    </div>
  );
}
