/**
 * Debug session management hook.
 * Manages breakpoints, watches, stepping, and session lifecycle.
 * Communicates with the OptiScript Rust backend via `window.__optiscript`.
 */
import { useState, useCallback, useRef } from 'react';
import { dacpInvoke, isDacpAvailable } from '../lib/dacp-client';
import type {
  DebugSession,
  DebugActions,
  DebugStatus,
  StoppedReason,
  VariableCategory,
  BreakpointSpec,
  WatchExpression,
  HitCountEntry,
  IndicatorStateInfo,
} from '../types/debug';

// ---------------------------------------------------------------------------
// OptiScript Debug API — extends the injected bridge with debug commands
// ---------------------------------------------------------------------------

interface OptiScriptDebugApi {
  debugStart(source: string, barsJson?: string | null): Promise<void>;
  debugContinue(): Promise<void>;
  debugStepInto(): Promise<void>;
  debugStepOver(): Promise<void>;
  debugStepOut(): Promise<void>;
  debugStepNextBar(): Promise<void>;
  debugStepBackward(): Promise<void>;
  debugStop(): Promise<void>;
  debugRestart(): Promise<void>;
  debugSetBreakpoints(breakpoints: BreakpointSpec[]): Promise<void>;
  debugEvalExpression(expression: string): Promise<string>;
  debugGetState(): Promise<DebugSession>;
  debugSetVariable(name: string, value: string): Promise<unknown>;
  debugGetProfilerData(): Promise<{ hitCounts: HitCountEntry[]; totalInstructions: number; maxCount: number }>;
  debugGetIndicatorStates(): Promise<IndicatorStateInfo[]>;
}

// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------

const INITIAL_SESSION: DebugSession = {
  status: 'idle',
  currentBar: 0,
  totalBars: 0,
  currentLine: 0,
  callStack: [],
  variables: [],
  breakpoints: [],
  watches: [],
  profilerData: [],
  profilerMaxCount: 0,
  indicatorStates: [],
};

/**
 * Retrieve debug methods from the injected `window.__optiscript` bridge.
 *
 * Resolution order:
 *  1. `window.__optiscript` with debug methods already wired by the DeskModal host.
 *  2. Direct Tauri invoke via `window.__TAURI__` — used when OptiScript runs as
 *     a native Tauri webview (not an iframe plugin).
 *  3. `null` — standalone browser mode, no backend available.
 */
function getDebugApi(): Partial<OptiScriptDebugApi> | null {
  // 1. Try injected bridge (iframe plugin mode)
  const api = window.__optiscript;
  if (api && typeof (api as unknown as Record<string, unknown>).debugStart === 'function') {
    return api as unknown as Partial<OptiScriptDebugApi>;
  }

  // 2. Fallback: direct Tauri invoke (native webview mode)
  const tauriGlobal = (window as unknown as Record<string, unknown>).__TAURI__ as
    | { core?: { invoke?: (cmd: string, args?: Record<string, unknown>) => Promise<unknown> } }
    | undefined;
  const invoke = tauriGlobal?.core?.invoke;
  if (invoke) {
    return {
      debugStart: (source: string, barsJson?: string | null) =>
        invoke('optiscript_debug_start', { source, barsJson: barsJson ?? null }) as Promise<void>,
      debugContinue: () =>
        invoke('optiscript_debug_continue') as Promise<void>,
      debugStepInto: () =>
        invoke('optiscript_debug_step_into') as Promise<void>,
      debugStepOver: () =>
        invoke('optiscript_debug_step_over') as Promise<void>,
      debugStepOut: () =>
        invoke('optiscript_debug_step_out') as Promise<void>,
      debugStepNextBar: () =>
        invoke('optiscript_debug_step_next_bar') as Promise<void>,
      debugStepBackward: () =>
        invoke('optiscript_debug_step_backward') as Promise<void>,
      debugStop: () =>
        invoke('optiscript_debug_stop') as Promise<void>,
      debugRestart: () =>
        invoke('optiscript_debug_restart') as Promise<void>,
      debugSetBreakpoints: (bp: BreakpointSpec[]) =>
        invoke('optiscript_debug_set_breakpoints', { breakpoints: bp }) as Promise<void>,
      debugEvalExpression: (expr: string) =>
        invoke('optiscript_debug_eval_expression', { expression: expr }) as Promise<string>,
      debugGetState: () =>
        invoke('optiscript_debug_get_state') as Promise<DebugSession>,
      debugSetVariable: (name: string, value: string) =>
        invoke('optiscript_debug_set_variable', { name, value }),
      debugGetProfilerData: () =>
        invoke('optiscript_debug_get_profiler_data') as Promise<{ hitCounts: HitCountEntry[]; totalInstructions: number; maxCount: number }>,
      debugGetIndicatorStates: () =>
        invoke('optiscript_debug_get_indicator_states') as Promise<IndicatorStateInfo[]>,
    };
  }

  // 3. Fallback: DACP postMessage bridge (iframe inside DeskModal)
  if (isDacpAvailable()) {
    return {
      debugStart: (source: string, barsJson?: string | null) =>
        dacpInvoke('optiscriptDebugStart', { source, barsJson: barsJson ?? null }) as Promise<void>,
      debugContinue: () =>
        dacpInvoke('optiscriptDebugContinue') as Promise<void>,
      debugStepInto: () =>
        dacpInvoke('optiscriptDebugStepInto') as Promise<void>,
      debugStepOver: () =>
        dacpInvoke('optiscriptDebugStepOver') as Promise<void>,
      debugStepOut: () =>
        dacpInvoke('optiscriptDebugStepOut') as Promise<void>,
      debugStepNextBar: () =>
        dacpInvoke('optiscriptDebugStepNextBar') as Promise<void>,
      debugStepBackward: () =>
        dacpInvoke('optiscriptDebugStepBackward') as Promise<void>,
      debugStop: () =>
        dacpInvoke('optiscriptDebugStop') as Promise<void>,
      debugRestart: () =>
        dacpInvoke('optiscriptDebugRestart') as Promise<void>,
      debugSetBreakpoints: (bp: BreakpointSpec[]) =>
        dacpInvoke('optiscriptDebugSetBreakpoints', { breakpoints: bp }) as Promise<void>,
      debugEvalExpression: (expr: string) =>
        dacpInvoke('optiscriptDebugEvalExpression', { expression: expr }) as Promise<string>,
      debugGetState: () =>
        dacpInvoke('optiscriptDebugGetState') as Promise<DebugSession>,
      debugSetVariable: (name: string, value: string) =>
        dacpInvoke('optiscriptDebugSetVariable', { name, value }),
      debugGetProfilerData: () =>
        dacpInvoke('optiscriptDebugGetProfilerData') as Promise<{ hitCounts: HitCountEntry[]; totalInstructions: number; maxCount: number }>,
      debugGetIndicatorStates: () =>
        dacpInvoke('optiscriptDebugGetIndicatorStates') as Promise<IndicatorStateInfo[]>,
    };
  }

  return null;
}

/** Generate a short random ID for watch expressions. */
function watchId(): string {
  return `w_${Date.now().toString(36)}_${Math.random().toString(36).slice(2, 7)}`;
}

/**
 * Map a raw API response (Record<string, unknown>) to the DebugSession fields
 * that come from the backend. Local-only fields (breakpoints, watches) are NOT
 * included — callers must merge those from the previous state.
 */
function mapApiState(raw: Record<string, unknown>): Partial<DebugSession> {
  return {
    status: (raw.status as DebugStatus) ?? 'idle',
    currentBar: (raw.currentBar as number) ?? 0,
    totalBars: (raw.totalBars as number) ?? 0,
    currentLine: (raw.currentLine as number) ?? 0,
    stoppedReason: raw.stoppedReason as StoppedReason | undefined,
    callStack: ((raw.callStack as Array<Record<string, unknown>>) ?? []).map(
      (f: Record<string, unknown>, i: number) => ({
        id: (f.id as number) ?? i,
        functionName: (f.functionName as string) ?? '<unknown>',
        line: (f.line as number) ?? 0,
        column: (f.column as number) ?? 0,
      }),
    ),
    variables: ((raw.variables as Array<Record<string, unknown>>) ?? []).map(
      (v: Record<string, unknown>) => ({
        name: (v.name as string) ?? '',
        value: (v.value as string) ?? 'na',
        type: (v.varType as string) ?? (v.type as string) ?? 'unknown',
        category: ((v.category as string) ?? 'user') as VariableCategory,
        isNa: (v.isNa as boolean) ?? false,
      }),
    ),
    indicatorStates: ((raw.indicatorStates as Array<Record<string, unknown>>) ?? []).map(
      (s: Record<string, unknown>) => ({
        callSiteId: (s.callSiteId as number) ?? 0,
        description: (s.description as string) ?? '',
      }),
    ),
  };
}

/**
 * Best-effort broadcast of the current debug session state over FDC3.
 * Only fires when `window.__optiscript?.broadcast` is available (i.e. running
 * inside DeskModal with the channel API wired). Silent no-op otherwise.
 */
function broadcastDebugSession(session: Partial<DebugSession>): void {
  const broadcast = (window as unknown as Record<string, unknown>).__optiscript as
    | { broadcast?: (ctx: Record<string, unknown>) => void }
    | undefined;
  if (!broadcast?.broadcast) return;
  const status = session.status ?? 'idle';
  if (status === 'idle') return;
  broadcast.broadcast({
    type: 'optiscript.debug-session',
    id: { sessionId: 'current' },
    status,
    currentBar: session.currentBar ?? 0,
    currentLine: session.currentLine ?? 0,
  });
}

// ---------------------------------------------------------------------------
// Hook
// ---------------------------------------------------------------------------

export interface UseDebugSessionResult {
  session: DebugSession;
  actions: DebugActions;
}

export function useDebugSession(): UseDebugSessionResult {
  const [session, setSession] = useState<DebugSession>(INITIAL_SESSION);

  // Ref tracks the latest breakpoints so async callbacks (start, continue)
  // can synchronously read them without stale closure captures.
  const breakpointsRef = useRef<readonly BreakpointSpec[]>([]);
  breakpointsRef.current = session.breakpoints;

  // ----- Session lifecycle -------------------------------------------------

  const start = useCallback(async (source: string, barsJson?: string | null): Promise<void> => {
    setSession((prev) => ({ ...prev, status: 'running', stoppedReason: undefined }));
    const api = getDebugApi();
    if (!api?.debugStart) {
      // No backend available — revert to idle so UI does not stay stuck on "running".
      setSession((prev) => ({ ...prev, status: 'idle' }));
      return;
    }
    try {
      // Ensure breakpoints are synced to the backend BEFORE starting.
      // toggleBreakpoint sends fire-and-forget, so a fast F5 press could
      // race with the pending sync. Awaiting here guarantees consistency.
      if (api.debugSetBreakpoints) {
        await api.debugSetBreakpoints([...breakpointsRef.current]);
      }
      await api.debugStart(source, barsJson);
      const state = await api.debugGetState?.();
      if (state) {
        const mapped = mapApiState(state as unknown as Record<string, unknown>);
        broadcastDebugSession(mapped);
        setSession((prev) => ({
          ...prev,
          ...mapped,
          breakpoints: prev.breakpoints,
          watches: prev.watches,
        }));
      }
    } catch (err) {
      // Backend call failed — show as terminated so the debug UI stays visible
      // with the error message. User can click Stop/Debug again.
      const message = err instanceof Error ? err.message : String(err);
      setSession((prev) => ({
        ...prev,
        status: 'terminated',
        error: message || 'Debug session failed to start',
      }));
    }
  }, []);

  /** Helper: execute a debug command, fetch state, and update the session. */
  const execAndSync = useCallback(async (
    action: (api: Partial<OptiScriptDebugApi>) => Promise<void>,
    guard: (api: Partial<OptiScriptDebugApi>) => boolean,
  ): Promise<void> => {
    const api = getDebugApi();
    if (!api || !guard(api)) return;
    try {
      await action(api);
      const state = await api.debugGetState?.();
      if (state) {
        const mapped = mapApiState(state as unknown as Record<string, unknown>);
        broadcastDebugSession(mapped);
        setSession((prev) => ({
          ...prev,
          ...mapped,
          breakpoints: prev.breakpoints,
          watches: prev.watches,
        }));
      }
    } catch {
      // On error, revert to paused so the session doesn't get stuck.
      setSession((prev) => ({
        ...prev,
        status: prev.status === 'running' ? 'paused' : prev.status,
      }));
    }
  }, []);

  const continue_ = useCallback(async (): Promise<void> => {
    setSession((prev) => ({ ...prev, status: 'running', stoppedReason: undefined }));
    await execAndSync(
      (api) => api.debugContinue!(),
      (api) => !!api.debugContinue,
    );
  }, [execAndSync]);

  const stepInto = useCallback(async (): Promise<void> => {
    await execAndSync(
      (api) => api.debugStepInto!(),
      (api) => !!api.debugStepInto,
    );
  }, [execAndSync]);

  const stepOver = useCallback(async (): Promise<void> => {
    await execAndSync(
      (api) => api.debugStepOver!(),
      (api) => !!api.debugStepOver,
    );
  }, [execAndSync]);

  const stepOut = useCallback(async (): Promise<void> => {
    await execAndSync(
      (api) => api.debugStepOut!(),
      (api) => !!api.debugStepOut,
    );
  }, [execAndSync]);

  const stepNextBar = useCallback(async (): Promise<void> => {
    await execAndSync(
      (api) => api.debugStepNextBar!(),
      (api) => !!api.debugStepNextBar,
    );
  }, [execAndSync]);

  const stepBackward = useCallback(async (): Promise<void> => {
    await execAndSync(
      (api) => api.debugStepBackward!(),
      (api) => !!api.debugStepBackward,
    );
  }, [execAndSync]);

  const stop = useCallback(async (): Promise<void> => {
    const api = getDebugApi();
    try {
      if (api?.debugStop) {
        await api.debugStop();
      }
    } catch {
      // Best-effort stop — always reset local state.
    }
    setSession(INITIAL_SESSION);
  }, []);

  const restart = useCallback(async (): Promise<void> => {
    const api = getDebugApi();
    if (!api?.debugRestart) return;
    setSession((prev) => ({ ...prev, status: 'running', stoppedReason: undefined }));
    try {
      await api.debugRestart();
      const state = await api.debugGetState?.();
      if (state) {
        const mapped = mapApiState(state as unknown as Record<string, unknown>);
        broadcastDebugSession(mapped);
        setSession((prev) => ({
          ...prev,
          ...mapped,
          breakpoints: prev.breakpoints,
          watches: prev.watches,
        }));
      }
    } catch {
      setSession((prev) => ({ ...prev, status: 'idle' }));
    }
  }, []);

  // ----- Breakpoints -------------------------------------------------------

  const setBreakpoint = useCallback((line: number, spec?: Partial<BreakpointSpec>): void => {
    setSession((prev) => {
      const existing = prev.breakpoints.findIndex((bp) => bp.line === line);
      const newBp: BreakpointSpec = {
        line,
        enabled: true,
        verified: false,
        ...spec,
      };

      let next: readonly BreakpointSpec[];
      if (existing >= 0) {
        const copy = [...prev.breakpoints];
        copy[existing] = newBp;
        next = copy;
      } else {
        next = [...prev.breakpoints, newBp];
      }

      // Fire-and-forget sync to backend
      const api = getDebugApi();
      if (api?.debugSetBreakpoints) {
        void api.debugSetBreakpoints([...next]);
      }

      return { ...prev, breakpoints: next };
    });
  }, []);

  const removeBreakpoint = useCallback((line: number): void => {
    setSession((prev) => {
      const next = prev.breakpoints.filter((bp) => bp.line !== line);

      const api = getDebugApi();
      if (api?.debugSetBreakpoints) {
        void api.debugSetBreakpoints([...next]);
      }

      return { ...prev, breakpoints: next };
    });
  }, []);

  const toggleBreakpoint = useCallback((line: number): void => {
    setSession((prev) => {
      const idx = prev.breakpoints.findIndex((bp) => bp.line === line);
      if (idx < 0) {
        // No breakpoint on this line — add one.
        const newBp: BreakpointSpec = { line, enabled: true, verified: false };
        const next = [...prev.breakpoints, newBp];

        const api = getDebugApi();
        if (api?.debugSetBreakpoints) {
          void api.debugSetBreakpoints([...next]);
        }

        return { ...prev, breakpoints: next };
      }

      const copy = [...prev.breakpoints];
      copy[idx] = { ...copy[idx], enabled: !copy[idx].enabled };

      const api = getDebugApi();
      if (api?.debugSetBreakpoints) {
        void api.debugSetBreakpoints([...copy]);
      }

      return { ...prev, breakpoints: copy };
    });
  }, []);

  // ----- Watch expressions -------------------------------------------------

  const addWatch = useCallback((expression: string): void => {
    const newWatch: WatchExpression = {
      id: watchId(),
      expression,
      value: '',
    };
    setSession((prev) => ({
      ...prev,
      watches: [...prev.watches, newWatch],
    }));
  }, []);

  const removeWatch = useCallback((id: string): void => {
    setSession((prev) => ({
      ...prev,
      watches: prev.watches.filter((w) => w.id !== id),
    }));
  }, []);

  // ----- Variable override --------------------------------------------------

  const setVariable = useCallback(async (name: string, value: string): Promise<void> => {
    const api = getDebugApi();
    if (!api?.debugSetVariable) return;
    const state = await api.debugSetVariable(name, value);
    if (state) {
      const mapped = mapApiState(state as Record<string, unknown>);
      broadcastDebugSession(mapped);
      setSession(prev => ({
        ...prev,
        ...mapped,
        breakpoints: prev.breakpoints,
        watches: prev.watches,
      }));
    }
  }, []);

  // ----- Expression evaluation ---------------------------------------------

  const evalExpression = useCallback(async (expression: string): Promise<string> => {
    const api = getDebugApi();
    if (!api?.debugEvalExpression) return '';
    return api.debugEvalExpression(expression);
  }, []);

  // ----- Profiler data retrieval -------------------------------------------

  const getProfilerData = useCallback(async (): Promise<void> => {
    const api = getDebugApi();
    if (!api?.debugGetProfilerData) return;
    const result = await api.debugGetProfilerData();
    if (result) {
      setSession((prev) => ({
        ...prev,
        profilerData: result.hitCounts,
        profilerMaxCount: result.maxCount,
      }));
    }
  }, []);

  // ----- Assemble result ---------------------------------------------------

  const actions: DebugActions = {
    start,
    continue_,
    stepInto,
    stepOver,
    stepOut,
    stepNextBar,
    stepBackward,
    stop,
    restart,
    setBreakpoint,
    removeBreakpoint,
    toggleBreakpoint,
    addWatch,
    removeWatch,
    evalExpression,
    setVariable,
    getProfilerData,
  };

  return { session, actions };
}

export default useDebugSession;
