/**
 * ScriptLibrary — Save, load, organize, and search OptiScript scripts.
 *
 * Features: category sidebar, fuzzy search, tags, import/export.
 */
import { useState, useMemo, useCallback } from 'react';
import type { SavedScript, ScriptCategory } from '../../types';
import styles from './ScriptLibrary.module.css';

interface ScriptLibraryProps {
  /** All saved scripts */
  scripts: readonly SavedScript[];
  /** Called when user selects a script to load into the editor */
  onLoad: (script: SavedScript) => void;
  /** Called when user wants to save the current script */
  onSave?: () => void;
  /** Called when user deletes a script */
  onDelete?: (id: string) => void;
  /** Called when user exports a script */
  onExport?: (script: SavedScript) => void;
}

/** Simple fuzzy match: checks if all characters of query appear in order in target */
function fuzzyMatch(query: string, target: string): boolean {
  const lower = target.toLowerCase();
  const q = query.toLowerCase();
  let qi = 0;

  for (let i = 0; i < lower.length && qi < q.length; i++) {
    if (lower[i] === q[qi]) qi++;
  }

  return qi === q.length;
}

function buildCategories(scripts: readonly SavedScript[]): ScriptCategory[] {
  const counts = new Map<string, number>();
  counts.set('all', scripts.length);

  for (const script of scripts) {
    const cat = script.category || 'Uncategorized';
    counts.set(cat, (counts.get(cat) ?? 0) + 1);
  }

  const categories: ScriptCategory[] = [
    { id: 'all', name: 'All Scripts', count: counts.get('all') ?? 0 },
  ];

  for (const [id, count] of counts) {
    if (id !== 'all') {
      categories.push({ id, name: id, count });
    }
  }

  return categories;
}

function formatDate(iso: string): string {
  try {
    const date = new Date(iso);
    return date.toLocaleDateString(undefined, {
      month: 'short',
      day: 'numeric',
      year: 'numeric',
    });
  } catch {
    return iso;
  }
}

export function ScriptLibrary({
  scripts,
  onLoad,
  onSave,
  onDelete,
  onExport,
}: ScriptLibraryProps) {
  const [searchQuery, setSearchQuery] = useState('');
  const [activeCategory, setActiveCategory] = useState('all');

  const categories = useMemo(() => buildCategories(scripts), [scripts]);

  const filteredScripts = useMemo(() => {
    let filtered = scripts;

    // Filter by category
    if (activeCategory !== 'all') {
      filtered = filtered.filter(
        (s) => (s.category || 'Uncategorized') === activeCategory,
      );
    }

    // Filter by search query
    if (searchQuery.trim()) {
      filtered = filtered.filter(
        (s) =>
          fuzzyMatch(searchQuery, s.name) ||
          s.tags.some((t) => fuzzyMatch(searchQuery, t)),
      );
    }

    return filtered;
  }, [scripts, activeCategory, searchQuery]);

  const handleDoubleClick = useCallback(
    (script: SavedScript) => {
      onLoad(script);
    },
    [onLoad],
  );

  const handleCardKeyDown = useCallback(
    (event: React.KeyboardEvent, script: SavedScript) => {
      if (event.key === 'Enter') {
        event.preventDefault();
        onLoad(script);
      }
    },
    [onLoad],
  );

  return (
    <div className={styles.container} role="region" aria-label="Script Library">
      <div className={styles.toolbar} role="toolbar" aria-label="Library toolbar">
        <div className={styles.searchContainer}>
          <span className={styles.searchIcon} aria-hidden="true">
            {'\u2315'}
          </span>
          <input
            type="search"
            className={styles.searchInput}
            placeholder="Search scripts..."
            value={searchQuery}
            onChange={(e) => setSearchQuery(e.target.value)}
            aria-label="Search scripts"
          />
        </div>
        {onSave && (
          <button
            className={styles.addButton}
            onClick={onSave}
            aria-label="Save current script to library"
            type="button"
          >
            Save Script
          </button>
        )}
      </div>

      <div className={styles.content}>
        <nav className={styles.sidebar} role="navigation" aria-label="Script categories">
          {categories.map((cat) => (
            <button
              key={cat.id}
              className={`${styles.categoryItem} ${
                activeCategory === cat.id ? styles.categoryItemActive : ''
              }`}
              onClick={() => setActiveCategory(cat.id)}
              aria-current={activeCategory === cat.id ? 'true' : undefined}
              type="button"
            >
              {cat.name}
              <span className={styles.categoryCount}>{cat.count}</span>
            </button>
          ))}
        </nav>

        {filteredScripts.length === 0 ? (
          <div className={styles.empty} role="status">
            {searchQuery
              ? `No scripts matching "${searchQuery}"`
              : 'No scripts in this category'}
          </div>
        ) : (
          <div className={styles.scriptList} role="list" aria-label="Scripts">
            {filteredScripts.map((script) => (
              <div
                key={script.id}
                className={styles.scriptCard}
                role="listitem"
                tabIndex={0}
                onDoubleClick={() => handleDoubleClick(script)}
                onKeyDown={(e) => handleCardKeyDown(e, script)}
                aria-label={`${script.name} (${script.scriptType}, v${script.version})`}
              >
                <div className={styles.scriptCardHeader}>
                  <span className={styles.scriptName}>{script.name}</span>
                  <span className={styles.scriptVersion}>v{script.version}</span>
                </div>

                <div className={styles.scriptMeta}>
                  <span className={styles.scriptType}>{script.scriptType}</span>
                  <span className={styles.scriptDate}>
                    {formatDate(script.updatedAt)}
                  </span>
                </div>

                {script.tags.length > 0 && (
                  <div className={styles.scriptTags}>
                    {script.tags.map((tag) => (
                      <span key={tag} className={styles.tag}>
                        {tag}
                      </span>
                    ))}
                  </div>
                )}

                <div className={styles.scriptActions}>
                  <button
                    className={styles.actionButton}
                    onClick={(e) => {
                      e.stopPropagation();
                      onLoad(script);
                    }}
                    aria-label={`Open ${script.name}`}
                    type="button"
                  >
                    Open
                  </button>
                  {onExport && (
                    <button
                      className={styles.actionButton}
                      onClick={(e) => {
                        e.stopPropagation();
                        onExport(script);
                      }}
                      aria-label={`Export ${script.name}`}
                      type="button"
                    >
                      Export
                    </button>
                  )}
                  {onDelete && (
                    <button
                      className={styles.actionButton}
                      onClick={(e) => {
                        e.stopPropagation();
                        onDelete(script.id);
                      }}
                      aria-label={`Delete ${script.name}`}
                      type="button"
                    >
                      Delete
                    </button>
                  )}
                </div>
              </div>
            ))}
          </div>
        )}
      </div>
    </div>
  );
}
