/**
 * BarNavigator -- horizontal bar navigation control for the OptiScript debugger.
 *
 * Layout: [< Prev] [---slider---] [Next >] [currentBar / totalBars]
 *
 * Allows stepping through bars via prev/next buttons or by scrubbing the
 * range slider to jump directly to a specific bar.
 */
import styles from './BarNavigator.module.css';

interface BarNavigatorProps {
  /** Zero-based index of the current bar. */
  readonly currentBar: number;
  /** Total number of bars in the dataset. */
  readonly totalBars: number;
  /** Jump directly to a specific bar index. */
  onBarChange: (bar: number) => void;
  /** Step forward one bar. */
  onStepNextBar: () => void;
  /** Step backward one bar. */
  onStepPrevBar: () => void;
}

export function BarNavigator({
  currentBar,
  totalBars,
  onBarChange,
  onStepNextBar,
  onStepPrevBar,
}: BarNavigatorProps) {
  const maxBar = Math.max(0, totalBars - 1);
  const isAtStart = currentBar <= 0;
  const isAtEnd = currentBar >= maxBar;
  const isEmpty = totalBars <= 0;

  const handleSliderChange = (event: React.ChangeEvent<HTMLInputElement>) => {
    onBarChange(Number(event.target.value));
  };

  return (
    <div
      className={styles.container}
      role="group"
      aria-label="Bar navigation"
    >
      <button
        className={styles.stepButton}
        onClick={onStepPrevBar}
        disabled={isAtStart || isEmpty}
        aria-label="Previous bar"
        type="button"
      >
        <span aria-hidden="true">{'\u25C0'}</span>
      </button>

      <input
        className={styles.slider}
        type="range"
        min={0}
        max={maxBar}
        value={currentBar}
        onChange={handleSliderChange}
        disabled={isEmpty}
        aria-label="Bar position"
        aria-valuemin={0}
        aria-valuemax={maxBar}
        aria-valuenow={currentBar}
        aria-valuetext={`Bar ${currentBar} of ${totalBars}`}
      />

      <button
        className={styles.stepButton}
        onClick={onStepNextBar}
        disabled={isAtEnd || isEmpty}
        aria-label="Next bar"
        type="button"
      >
        <span aria-hidden="true">{'\u25B6'}</span>
      </button>

      <span className={styles.barDisplay} aria-live="polite">
        <span className={styles.barCurrent}>{currentBar}</span>
        <span className={styles.barSeparator}>/</span>
        <span className={styles.barTotal}>{totalBars}</span>
      </span>
    </div>
  );
}
