/**
 * useScriptStorage — Persist scripts to DeskModal appStorage with localStorage fallback.
 *
 * When running inside DeskModal, uses `window.deskmodal.appStorage` for
 * cross-session persistence. In standalone browser mode, falls back to
 * localStorage. DEMO_SCRIPTS are seeded when storage is empty.
 */
import { useState, useEffect, useCallback, useRef } from 'react';
import type { SavedScript } from '../types';

const STORAGE_PREFIX = 'optiscript/scripts/';
const LOCAL_STORAGE_KEY = 'optiscript-scripts';

/**
 * Load scripts from DeskModal appStorage.
 * Returns null if the API is unavailable.
 */
async function loadFromAppStorage(): Promise<SavedScript[] | null> {
  const storage = window.deskmodal?.appStorage;
  if (!storage) return null;

  try {
    const keys = await storage.list(STORAGE_PREFIX);
    const scripts: SavedScript[] = [];

    for (const key of keys) {
      try {
        const raw = await storage.get(key);
        if (raw) {
          scripts.push(JSON.parse(raw) as SavedScript);
        }
      } catch {
        // Skip malformed entries
      }
    }

    return scripts;
  } catch {
    return null;
  }
}

/** Load scripts from localStorage. Returns empty array on failure. */
function loadFromLocalStorage(): SavedScript[] {
  try {
    const raw = localStorage.getItem(LOCAL_STORAGE_KEY);
    if (raw) {
      return JSON.parse(raw) as SavedScript[];
    }
  } catch {
    // Corrupted or unavailable
  }
  return [];
}

/** Save the full script list to localStorage. */
function saveToLocalStorage(scripts: readonly SavedScript[]): void {
  try {
    localStorage.setItem(LOCAL_STORAGE_KEY, JSON.stringify(scripts));
  } catch {
    // localStorage may be full or unavailable
  }
}

/** Save a single script to DeskModal appStorage. */
async function saveToAppStorage(script: SavedScript): Promise<boolean> {
  const storage = window.deskmodal?.appStorage;
  if (!storage) return false;

  try {
    await storage.set(`${STORAGE_PREFIX}${script.id}`, JSON.stringify(script));
    return true;
  } catch {
    return false;
  }
}

/** Delete a single script from DeskModal appStorage. */
async function deleteFromAppStorage(id: string): Promise<boolean> {
  const storage = window.deskmodal?.appStorage;
  if (!storage) return false;

  try {
    await storage.delete(`${STORAGE_PREFIX}${id}`);
    return true;
  } catch {
    return false;
  }
}

export interface UseScriptStorageResult {
  scripts: SavedScript[];
  isLoading: boolean;
  addScript: (script: SavedScript) => void;
  deleteScript: (id: string) => void;
  updateScript: (script: SavedScript) => void;
}

export function useScriptStorage(
  defaultScripts: readonly SavedScript[],
): UseScriptStorageResult {
  const [scripts, setScripts] = useState<SavedScript[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const hasInitialized = useRef(false);

  // Load on mount
  useEffect(() => {
    if (hasInitialized.current) return;
    hasInitialized.current = true;

    let cancelled = false;

    async function load(): Promise<void> {
      // Try DeskModal appStorage first
      const appStorageScripts = await loadFromAppStorage();
      if (cancelled) return;

      if (appStorageScripts !== null) {
        if (appStorageScripts.length > 0) {
          setScripts(appStorageScripts);
        } else {
          // Seed defaults into appStorage
          for (const s of defaultScripts) {
            await saveToAppStorage(s as SavedScript);
          }
          if (!cancelled) {
            setScripts([...defaultScripts] as SavedScript[]);
          }
        }
      } else {
        // Fallback to localStorage
        const localScripts = loadFromLocalStorage();
        if (localScripts.length > 0) {
          setScripts(localScripts);
        } else {
          // Seed defaults
          const defaults = [...defaultScripts] as SavedScript[];
          setScripts(defaults);
          saveToLocalStorage(defaults);
        }
      }

      if (!cancelled) setIsLoading(false);
    }

    void load();

    return () => {
      cancelled = true;
    };
  }, [defaultScripts]);

  const addScript = useCallback((script: SavedScript) => {
    setScripts((prev) => {
      const next = [script, ...prev];
      // Persist
      void saveToAppStorage(script).then((saved) => {
        if (!saved) saveToLocalStorage(next);
      });
      saveToLocalStorage(next);
      return next;
    });
  }, []);

  const deleteScript = useCallback((id: string) => {
    setScripts((prev) => {
      const next = prev.filter((s) => s.id !== id);
      void deleteFromAppStorage(id).then((deleted) => {
        if (!deleted) saveToLocalStorage(next);
      });
      saveToLocalStorage(next);
      return next;
    });
  }, []);

  const updateScript = useCallback((script: SavedScript) => {
    setScripts((prev) => {
      const next = prev.map((s) => (s.id === script.id ? script : s));
      void saveToAppStorage(script).then((saved) => {
        if (!saved) saveToLocalStorage(next);
      });
      saveToLocalStorage(next);
      return next;
    });
  }, []);

  return { scripts, isLoading, addScript, deleteScript, updateScript };
}
