/**
 * BacktestViewer — Displays backtest performance metrics, equity curve, and trades.
 *
 * Tabs: Summary, Equity Curve, Trade List.
 */
import { useState, useMemo, useCallback, useRef } from 'react';
import type { BacktestResult, BacktestTrade } from '../../types';
import styles from './BacktestViewer.module.css';

type BacktestTab = 'summary' | 'equity' | 'trades';

interface BacktestViewerProps {
  /** Backtest result data */
  result: BacktestResult | null;
}

function formatCurrency(value: number): string {
  return value.toLocaleString(undefined, {
    minimumFractionDigits: 2,
    maximumFractionDigits: 2,
  });
}

function formatPercent(value: number): string {
  return `${value >= 0 ? '+' : ''}${value.toFixed(2)}%`;
}

function formatRatio(value: number): string {
  return value.toFixed(2);
}

const BACKTEST_TABS: BacktestTab[] = ['summary', 'equity', 'trades'];

export function BacktestViewer({ result }: BacktestViewerProps) {
  const [activeTab, setActiveTab] = useState<BacktestTab>('summary');
  const backtestTablistRef = useRef<HTMLDivElement>(null);

  const handleBacktestTablistKeyDown = useCallback(
    (event: React.KeyboardEvent) => {
      const tabButtons = backtestTablistRef.current?.querySelectorAll<HTMLButtonElement>('[role="tab"]');
      if (!tabButtons || tabButtons.length === 0) return;

      const currentIndex = BACKTEST_TABS.indexOf(activeTab);
      let nextIndex = -1;

      switch (event.key) {
        case 'ArrowRight':
          nextIndex = (currentIndex + 1) % BACKTEST_TABS.length;
          break;
        case 'ArrowLeft':
          nextIndex = (currentIndex - 1 + BACKTEST_TABS.length) % BACKTEST_TABS.length;
          break;
        case 'Home':
          nextIndex = 0;
          break;
        case 'End':
          nextIndex = BACKTEST_TABS.length - 1;
          break;
        default:
          return;
      }

      event.preventDefault();
      setActiveTab(BACKTEST_TABS[nextIndex]);
      tabButtons[nextIndex]?.focus();
    },
    [activeTab],
  );

  if (!result) {
    return (
      <div className={styles.container} role="region" aria-label="Backtest results">
        <div className={styles.empty}>
          No backtest results.
          <br />
          Run a strategy script to see performance metrics.
        </div>
      </div>
    );
  }

  const { metrics } = result;

  return (
    <div className={styles.container} role="region" aria-label="Backtest results">
      <div className={styles.header}>
        <div>
          <div className={styles.title}>{result.scriptName}</div>
          <div className={styles.subtitle}>
            {result.instrument} {'\u00B7'} {result.timeframe} {'\u00B7'}{' '}
            {result.dateRange.start} to {result.dateRange.end}
          </div>
        </div>

        <div
          ref={backtestTablistRef}
          className={styles.tabBar}
          role="tablist"
          aria-label="Backtest views"
          onKeyDown={handleBacktestTablistKeyDown}
        >
          {(['summary', 'equity', 'trades'] as const).map((tab) => (
            <button
              key={tab}
              className={`${styles.tabButton} ${activeTab === tab ? styles.tabButtonActive : ''}`}
              onClick={() => setActiveTab(tab)}
              role="tab"
              aria-selected={activeTab === tab}
              aria-controls={`panel-${tab}`}
              tabIndex={activeTab === tab ? 0 : -1}
              type="button"
            >
              {tab === 'summary' ? 'Summary' : tab === 'equity' ? 'Equity' : 'Trades'}
            </button>
          ))}
        </div>
      </div>

      <div className={styles.body} role="tabpanel" id={`panel-${activeTab}`}>
        {activeTab === 'summary' && (
          <SummaryView metrics={metrics} />
        )}
        {activeTab === 'equity' && (
          <EquityView result={result} />
        )}
        {activeTab === 'trades' && (
          <TradesView trades={result.trades} />
        )}
      </div>
    </div>
  );
}

function SummaryView({ metrics }: { metrics: BacktestResult['metrics'] }) {
  return (
    <>
      {/* Key metrics cards */}
      <div className={styles.metricsGrid}>
        <MetricCard
          label="Net Profit"
          value={`$${formatCurrency(metrics.netProfit)}`}
          subtext={formatPercent(metrics.netProfitPercent)}
          positive={metrics.netProfit >= 0}
        />
        <MetricCard
          label="Total Trades"
          value={String(metrics.totalTrades)}
        />
        <MetricCard
          label="Win Rate"
          value={`${(metrics.winRate * 100).toFixed(1)}%`}
          positive={metrics.winRate >= 0.5}
        />
        <MetricCard
          label="Profit Factor"
          value={formatRatio(metrics.profitFactor)}
          positive={metrics.profitFactor >= 1}
        />
        <MetricCard
          label="Sharpe Ratio"
          value={formatRatio(metrics.sharpeRatio)}
          positive={metrics.sharpeRatio >= 0}
        />
        <MetricCard
          label="Max Drawdown"
          value={`$${formatCurrency(Math.abs(metrics.maxDrawdown))}`}
          subtext={formatPercent(metrics.maxDrawdownPercent)}
          positive={false}
        />
      </div>

      {/* Detailed stats */}
      <div className={styles.summaryGrid}>
        <div className={styles.summarySection}>
          <div className={styles.summarySectionTitle}>Performance</div>
          <SummaryRow label="Gross Profit" value={`$${formatCurrency(metrics.grossProfit)}`} />
          <SummaryRow label="Gross Loss" value={`$${formatCurrency(metrics.grossLoss)}`} />
          <SummaryRow label="Average Trade" value={`$${formatCurrency(metrics.averageTrade)}`} />
          <SummaryRow label="Average Win" value={`$${formatCurrency(metrics.averageWin)}`} />
          <SummaryRow label="Average Loss" value={`$${formatCurrency(metrics.averageLoss)}`} />
          <SummaryRow label="Largest Win" value={`$${formatCurrency(metrics.largestWin)}`} />
          <SummaryRow label="Largest Loss" value={`$${formatCurrency(metrics.largestLoss)}`} />
        </div>

        <div className={styles.summarySection}>
          <div className={styles.summarySectionTitle}>Statistics</div>
          <SummaryRow label="Winning Trades" value={String(metrics.winningTrades)} />
          <SummaryRow label="Losing Trades" value={String(metrics.losingTrades)} />
          <SummaryRow label="Sortino Ratio" value={formatRatio(metrics.sortinoRatio)} />
          <SummaryRow label="Avg Bars in Trade" value={String(metrics.averageBarsInTrade)} />
          <SummaryRow label="Initial Capital" value={`$${formatCurrency(metrics.initialCapital)}`} />
          <SummaryRow label="Final Equity" value={`$${formatCurrency(metrics.finalEquity)}`} />
        </div>
      </div>
    </>
  );
}

function MetricCard({
  label,
  value,
  subtext,
  positive,
}: {
  label: string;
  value: string;
  subtext?: string;
  positive?: boolean;
}) {
  const valueClass = positive === true
    ? styles.metricValuePositive
    : positive === false
      ? styles.metricValueNegative
      : styles.metricValue;

  return (
    <div className={styles.metricCard}>
      <span className={styles.metricLabel}>{label}</span>
      <span className={`${styles.metricValue} ${valueClass}`}>{value}</span>
      {subtext && <span className={styles.metricSubtext}>{subtext}</span>}
    </div>
  );
}

function SummaryRow({ label, value }: { label: string; value: string }) {
  return (
    <div className={styles.summaryRow}>
      <span className={styles.summaryLabel}>{label}</span>
      <span className={styles.summaryValue}>{value}</span>
    </div>
  );
}

function EquityView({ result }: { result: BacktestResult }) {
  const { equityCurve, metrics } = result;

  const svgData = useMemo(() => {
    if (equityCurve.length === 0) return null;

    const width = 800;
    const height = 200;
    const padding = { top: 10, right: 10, bottom: 10, left: 10 };
    const chartWidth = width - padding.left - padding.right;
    const chartHeight = height - padding.top - padding.bottom;

    const equityValues = equityCurve.map((p) => p.equity);
    const minVal = Math.min(...equityValues);
    const maxVal = Math.max(...equityValues);
    const range = maxVal - minVal || 1;

    const points = equityCurve.map((point, i) => {
      const x = padding.left + (i / (equityCurve.length - 1)) * chartWidth;
      const y = padding.top + (1 - (point.equity - minVal) / range) * chartHeight;
      return `${x},${y}`;
    });

    // Gradient fill area
    const areaPoints = [
      `${padding.left},${height - padding.bottom}`,
      ...points,
      `${width - padding.right},${height - padding.bottom}`,
    ];

    return {
      width,
      height,
      linePath: `M ${points.join(' L ')}`,
      areaPath: `M ${areaPoints.join(' L ')} Z`,
      isPositive: metrics.netProfit >= 0,
    };
  }, [equityCurve, metrics.netProfit]);

  if (!svgData) {
    return (
      <div className={styles.empty}>No equity curve data available.</div>
    );
  }

  const strokeColor = svgData.isPositive ? 'var(--deskmodal-accent-default)' : 'var(--deskmodal-error)';
  const fillColor = svgData.isPositive
    ? 'rgba(30, 91, 255, 0.1)'
    : 'rgba(255, 106, 0, 0.1)';

  return (
    <div className={styles.chartContainer}>
      <div className={styles.chartTitle}>Equity Curve</div>
      <svg
        className={styles.chartSvg}
        viewBox={`0 0 ${svgData.width} ${svgData.height}`}
        preserveAspectRatio="none"
        role="img"
        aria-label={`Equity curve chart. Final equity: $${formatCurrency(metrics.finalEquity)}`}
      >
        <path d={svgData.areaPath} fill={fillColor} />
        <path
          d={svgData.linePath}
          fill="none"
          stroke={strokeColor}
          strokeWidth="2"
          vectorEffect="non-scaling-stroke"
        />
      </svg>
    </div>
  );
}

function TradesView({ trades }: { trades: readonly BacktestTrade[] }) {
  if (trades.length === 0) {
    return (
      <div className={styles.empty}>No trade data available.</div>
    );
  }

  return (
    <div className={styles.tableContainer}>
      <table className={styles.table} role="table" aria-label="Trade history">
        <thead>
          <tr>
            <th scope="col">#</th>
            <th scope="col">Direction</th>
            <th scope="col">Entry</th>
            <th scope="col">Exit</th>
            <th scope="col">Qty</th>
            <th scope="col">Profit</th>
            <th scope="col">P%</th>
            <th scope="col">Bars</th>
            <th scope="col">Entry Reason</th>
            <th scope="col">Exit Reason</th>
          </tr>
        </thead>
        <tbody>
          {trades.map((trade) => (
            <tr key={trade.id}>
              <td>{trade.id}</td>
              <td className={trade.direction === 'long' ? styles.directionLong : styles.directionShort}>
                {trade.direction.toUpperCase()}
              </td>
              <td>{trade.entryPrice.toFixed(2)}</td>
              <td>{trade.exitPrice.toFixed(2)}</td>
              <td>{trade.quantity}</td>
              <td className={trade.profit >= 0 ? styles.profitPositive : styles.profitNegative}>
                ${formatCurrency(trade.profit)}
              </td>
              <td className={trade.profitPercent >= 0 ? styles.profitPositive : styles.profitNegative}>
                {formatPercent(trade.profitPercent)}
              </td>
              <td>{trade.bars}</td>
              <td>{trade.entryReason}</td>
              <td>{trade.exitReason}</td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
}
