/**
 * OptiScript Monarch Language Definition for Monaco Editor
 *
 * Version-aware syntax highlighting for OptiScript v2-v6.
 * Token types: keywords, built-ins, operators, strings, numbers, comments, annotations.
 */
import type * as monaco from 'monaco-editor';
import type { OptiVersion } from '../types';

/** Keywords available in OptiScript v2 (baseline) */
const KEYWORDS_V2 = [
  'if', 'else', 'for', 'to', 'by', 'and', 'or', 'not',
  'true', 'false', 'na', 'study', 'strategy', 'plot', 'input',
  'return',
];

/** Additional keywords in v3 */
const KEYWORDS_V3 = [':='];

/** Additional keywords in v4 */
const KEYWORDS_V4 = [
  'var', 'indicator', 'array', 'line', 'label', 'box', 'alert',
];

/** Additional keywords in v5 */
const KEYWORDS_V5 = [
  'varip', 'switch', 'while', 'type', 'method', 'import', 'export',
  'library', 'map', 'matrix', 'table',
];

/** Additional keywords in v6 */
const KEYWORDS_V6 = ['enum'];

/** Built-in constants */
const CONSTANTS = [
  'close', 'open', 'high', 'low', 'volume', 'time', 'time_close',
  'hl2', 'hlc3', 'ohlc4', 'bar_index', 'timenow', 'dayofweek',
  'dayofmonth', 'weekofyear', 'month', 'year', 'hour', 'minute', 'second',
  'last_bar_index', 'last_bar_time', 'barstate',
  'syminfo', 'timeframe', 'session', 'strategy',
  'adjustment', 'barmerge', 'color', 'currency', 'display', 'earnings',
  'dividends', 'extend', 'font', 'format', 'hline', 'input',
  'location', 'math', 'order', 'plot', 'position', 'scale',
  'shape', 'size', 'ta', 'text', 'xloc', 'yloc',
  'alert', 'log', 'runtime', 'str', 'ticker', 'request',
];

/** Built-in namespace prefixes for dot-notation highlighting */
const NAMESPACES = [
  'ta', 'math', 'str', 'array', 'map', 'matrix', 'table',
  'color', 'input', 'request', 'strategy', 'line', 'label',
  'box', 'ticker', 'log', 'runtime', 'session', 'syminfo',
  'timeframe', 'barstate', 'chart',
];

/**
 * Returns the full set of keywords for a given OptiScript version.
 */
export function getKeywordsForVersion(version: OptiVersion): string[] {
  const keywords = [...KEYWORDS_V2];
  if (version >= 3) keywords.push(...KEYWORDS_V3);
  if (version >= 4) keywords.push(...KEYWORDS_V4);
  if (version >= 5) keywords.push(...KEYWORDS_V5);
  if (version >= 6) keywords.push(...KEYWORDS_V6);
  return keywords;
}

/**
 * Creates a Monarch language definition for OptiScript.
 */
export function createOptiScriptLanguage(
  version: OptiVersion = 5,
): monaco.languages.IMonarchLanguage {
  const keywords = getKeywordsForVersion(version);

  return {
    defaultToken: '',
    tokenPostfix: '.opti',

    keywords,
    constants: CONSTANTS,
    namespaces: NAMESPACES,

    operators: [
      '+', '-', '*', '/', '%',
      '==', '!=', '<', '>', '<=', '>=',
      '=', ':=', '+=', '-=', '*=', '/=', '%=',
      '?', ':',
      '=>',
    ],

    symbols: /[=><!~?:&|+\-*/^%]+/,
    escapes: /\\(?:[abfnrtv\\"']|x[0-9A-Fa-f]{1,4}|u[0-9A-Fa-f]{4}|U[0-9A-Fa-f]{8})/,

    tokenizer: {
      root: [
        // Version annotation — escape @ as \x40 to avoid Monarch attribute reference
        [/\/\/\x40version=\d+/, 'annotation'],

        // Annotations: @description, @param, @returns, @type, @field
        [/\x40(description|param|returns|type|field)\b/, 'annotation'],

        // Line comment
        [/\/\/.*$/, 'comment'],

        // Block comment
        [/\/\*/, 'comment', '@comment'],

        // Strings
        [/"([^"\\]|\\.)*$/, 'string.invalid'], // unterminated
        [/'([^'\\]|\\.)*$/, 'string.invalid'], // unterminated
        [/"/, 'string', '@string_double'],
        [/'/, 'string', '@string_single'],

        // Numbers
        [/\d+\.\d*([eE][-+]?\d+)?/, 'number.float'],
        [/\.\d+([eE][-+]?\d+)?/, 'number.float'],
        [/\d+[eE][-+]?\d+/, 'number.float'],
        [/0[xX][0-9a-fA-F]+/, 'number.hex'],
        [/\d+/, 'number'],

        // Color literals (#RRGGBB, #RRGGBBAA)
        [/#[0-9a-fA-F]{6,8}\b/, 'number.hex'],

        // Namespace.function pattern
        [
          /([a-zA-Z_]\w*)(\.)/,
          {
            cases: {
              '$1@namespaces': ['namespace', 'delimiter'],
              '@default': ['identifier', 'delimiter'],
            },
          },
        ],

        // Identifiers and keywords
        [
          /[a-zA-Z_]\w*/,
          {
            cases: {
              '@keywords': 'keyword',
              '@constants': 'variable.predefined',
              '@default': 'identifier',
            },
          },
        ],

        // History reference operator
        [/\[/, 'delimiter.square', '@history_ref'],

        // Delimiters and operators
        [/[{}()]/, 'delimiter.bracket'],
        [/[,;]/, 'delimiter'],
        [
          /@symbols/,
          {
            cases: {
              '@operators': 'operator',
              '@default': '',
            },
          },
        ],

        // Whitespace
        [/[ \t\r\n]+/, ''],
      ],

      comment: [
        [/[^/*]+/, 'comment'],
        [/\*\//, 'comment', '@pop'],
        [/[/*]/, 'comment'],
      ],

      string_double: [
        [/[^\\"]+/, 'string'],
        [/@escapes/, 'string.escape'],
        [/\\./, 'string.escape.invalid'],
        [/"/, 'string', '@pop'],
      ],

      string_single: [
        [/[^\\']+/, 'string'],
        [/@escapes/, 'string.escape'],
        [/\\./, 'string.escape.invalid'],
        [/'/, 'string', '@pop'],
      ],

      history_ref: [
        [/\d+/, 'number'],
        [/[a-zA-Z_]\w*/, 'identifier'],
        [/\]/, 'delimiter.square', '@pop'],
        [/./, ''],
      ],
    },
  };
}

/**
 * Creates the Monaco language configuration (brackets, comments, etc.)
 */
export function createOptiScriptLanguageConfiguration(): monaco.languages.LanguageConfiguration {
  return {
    comments: {
      lineComment: '//',
      blockComment: ['/*', '*/'],
    },
    brackets: [
      ['(', ')'],
      ['[', ']'],
    ],
    autoClosingPairs: [
      { open: '(', close: ')' },
      { open: '[', close: ']' },
      { open: '"', close: '"', notIn: ['string'] },
      { open: "'", close: "'", notIn: ['string'] },
      { open: '/*', close: '*/', notIn: ['string'] },
    ],
    surroundingPairs: [
      { open: '(', close: ')' },
      { open: '[', close: ']' },
      { open: '"', close: '"' },
      { open: "'", close: "'" },
    ],
    folding: {
      offSide: true,
    },
    indentationRules: {
      increaseIndentPattern: /^\s*(if|else|for|while|switch|method|type|export)\b.*$/,
      decreaseIndentPattern: /^\s*(else)\b/,
    },
  };
}

/**
 * Creates a Monaco theme that matches the TradeSurface dark theme.
 * Maps OptiScript token types to colors from the --ts-* palette.
 *
 * Note: Monaco defineTheme requires hex values, not CSS variables.
 * Syntax highlighting colors (keywords, strings, etc.) are the language's
 * visual identity and stay as-is. UI chrome colors (background, gutter,
 * selection) align with the --ts-surface-* / --ts-accent-* palette.
 */
export function createOptiScriptDarkTheme(): monaco.editor.IStandaloneThemeData {
  return {
    base: 'vs-dark',
    inherit: true,
    rules: [
      { token: 'comment', foreground: '5C6370', fontStyle: 'italic' },
      { token: 'annotation', foreground: '8A8F98', fontStyle: 'italic' },
      { token: 'keyword', foreground: '5B8FFF' },
      { token: 'variable.predefined', foreground: 'E06C75' },
      { token: 'namespace', foreground: '61AFEF' },
      { token: 'identifier', foreground: 'D4D4D4' },
      { token: 'number', foreground: 'D19A66' },
      { token: 'number.float', foreground: 'D19A66' },
      { token: 'number.hex', foreground: 'D19A66' },
      { token: 'string', foreground: '98C379' },
      { token: 'string.escape', foreground: '56B6C2' },
      { token: 'string.invalid', foreground: 'FF6A00' },
      { token: 'operator', foreground: '56B6C2' },
      { token: 'delimiter', foreground: '8A8F98' },
      { token: 'delimiter.bracket', foreground: 'D4D4D4' },
      { token: 'delimiter.square', foreground: 'E06C75' },
    ],
    colors: {
      /* UI chrome — aligned to --ts-surface-* / --ts-accent-* */
      'editor.background': '#0c0e16',         /* --ts-surface-1 */
      'editor.foreground': '#D4D4D4',
      'editor.lineHighlightBackground': '#1a1c2833', /* --ts-surface-3 @ 20% */
      'editor.selectionBackground': '#3b82f633',     /* --ts-accent-default @ 20% */
      'editor.inactiveSelectionBackground': '#3b82f615',
      'editorLineNumber.foreground': '#4a4a5a',
      'editorLineNumber.activeForeground': '#8A8F98',
      'editorCursor.foreground': '#3b82f6',          /* --ts-accent-default */
      'editorIndentGuide.background': '#1a1c28',     /* --ts-surface-3 */
      'editorIndentGuide.activeBackground': '#222432', /* --ts-surface-4 */
      'editor.findMatchBackground': '#f59e0b40',
      'editor.findMatchHighlightBackground': '#3b82f625',
      'editorBracketMatch.background': '#3b82f620',
      'editorBracketMatch.border': '#3b82f6',
      'editorGutter.background': '#08090f',          /* --ts-surface-0 */
      'editorWidget.background': '#12141e',          /* --ts-surface-2 */
      'editorWidget.border': '#1a1c28',              /* --ts-surface-3 */
      'editorSuggestWidget.background': '#12141e',
      'editorSuggestWidget.border': '#1a1c28',
      'editorSuggestWidget.selectedBackground': '#3b82f620',
      'editorHoverWidget.background': '#12141e',
      'editorHoverWidget.border': '#1a1c28',
      'minimap.background': '#08090f',
      'scrollbar.shadow': '#000000',
      'scrollbarSlider.background': '#22243280',
      'scrollbarSlider.hoverBackground': '#5C637080',
      'scrollbarSlider.activeBackground': '#8A8F9880',
    },
  };
}

/**
 * Creates a Monaco theme that matches the TradeSurface light theme.
 */
export function createOptiScriptLightTheme(): monaco.editor.IStandaloneThemeData {
  return {
    base: 'vs',
    inherit: true,
    rules: [
      { token: 'comment', foreground: '8A8F98', fontStyle: 'italic' },
      { token: 'annotation', foreground: '5C6370', fontStyle: 'italic' },
      { token: 'keyword', foreground: '1548CC' },
      { token: 'variable.predefined', foreground: 'C04040' },
      { token: 'namespace', foreground: '2070B0' },
      { token: 'identifier', foreground: '0A0A0A' },
      { token: 'number', foreground: 'B07020' },
      { token: 'number.float', foreground: 'B07020' },
      { token: 'number.hex', foreground: 'B07020' },
      { token: 'string', foreground: '508050' },
      { token: 'string.escape', foreground: '2090A0' },
      { token: 'string.invalid', foreground: 'CC5500' },
      { token: 'operator', foreground: '2090A0' },
      { token: 'delimiter', foreground: '5C6370' },
      { token: 'delimiter.bracket', foreground: '0A0A0A' },
      { token: 'delimiter.square', foreground: 'C04040' },
    ],
    colors: {
      /* UI chrome — aligned to --ts-surface-* light palette */
      'editor.background': '#ffffff',         /* --ts-surface-1 */
      'editor.foreground': '#1a1a1a',
      'editor.lineHighlightBackground': '#0000000a',
      'editor.selectionBackground': '#2563eb22',  /* --ts-accent-default @ 13% */
      'editorLineNumber.foreground': '#999999',
      'editorLineNumber.activeForeground': '#5C6370',
      'editorCursor.foreground': '#2563eb',        /* --ts-accent-default light */
      'editorIndentGuide.background': '#e4e6ea',   /* --ts-surface-3 */
      'editorIndentGuide.activeBackground': '#d4d6dc', /* --ts-surface-4 */
      'editorGutter.background': '#f8f9fa',        /* --ts-surface-0 */
      'editorWidget.background': '#ffffff',
      'editorWidget.border': '#e4e6ea',
      'editorSuggestWidget.background': '#ffffff',
      'editorSuggestWidget.border': '#e4e6ea',
      'editorSuggestWidget.selectedBackground': '#2563eb15',
    },
  };
}

/**
 * Detects the OptiScript version from source code.
 */
export function detectVersion(source: string): OptiVersion {
  const match = source.match(/\/\/@version=(\d+)/);
  if (match) {
    const v = parseInt(match[1], 10);
    if (v >= 2 && v <= 6) return v as OptiVersion;
  }
  return 5; // default
}
