/**
 * DebugToolbar — Controls for the OptiScript debug session.
 *
 * Displays play/continue, pause, step (over/into/out/next-bar/backward),
 * stop, and restart buttons. Button enable/disable states reflect the
 * current session status. Also shows bar position and a status badge.
 *
 * Keyboard shortcuts are handled at the editor level, not here.
 */
import type { DebugSession, DebugActions } from '../../types/debug';
import styles from './DebugToolbar.module.css';

interface DebugToolbarProps {
  /** Current debug session state */
  session: DebugSession;
  /** Action callbacks wired to the debug engine */
  actions: DebugActions;
  /** Current editor source code, passed to the start action */
  source?: string;
}

/** Map session status to the CSS modifier class for the status dot. */
function statusDotClass(status: DebugSession['status']): string {
  switch (status) {
    case 'running':    return styles.statusDotRunning;
    case 'paused':     return styles.statusDotPaused;
    case 'idle':       return styles.statusDotIdle;
    case 'terminated': return styles.statusDotTerminated;
  }
}

export function DebugToolbar({ session, actions, source }: DebugToolbarProps) {
  const { status, currentBar, totalBars } = session;

  const isIdle       = status === 'idle';
  const isRunning    = status === 'running';
  const isPaused     = status === 'paused';
  const isTerminated = status === 'terminated';

  // Stepping controls are only available when paused
  const canStep = isPaused;

  return (
    <div
      className={styles.toolbar}
      role="toolbar"
      aria-label="Debug controls"
    >
      {/* ── Start / Continue ── */}
      <button
        className={`${styles.button} ${styles.buttonStart}`}
        onClick={() => {
          if (isIdle || isTerminated) {
            void actions.start(source ?? '');
          } else if (isPaused) {
            void actions.continue_();
          }
        }}
        disabled={isRunning}
        aria-label={isIdle || isTerminated ? 'Start debugging (F5)' : 'Continue (F5)'}
        title={isIdle || isTerminated ? 'Start debugging (F5)' : 'Continue (F5)'}
        type="button"
      >
        {'\u25B6'}
      </button>

      {/* ── Pause ── */}
      <button
        className={styles.button}
        disabled={true}
        aria-label="Pause (not available — VM executes synchronously)"
        title="Pause (not available — VM executes synchronously)"
        type="button"
      >
        {'\u23F8'}
      </button>

      <div className={styles.divider} aria-hidden="true" />

      {/* ── Step Over ── */}
      <button
        className={styles.button}
        onClick={() => void actions.stepOver()}
        disabled={!canStep}
        aria-label="Step Over (F10)"
        title="Step Over (F10)"
        type="button"
      >
        {'\u23ED'}
      </button>

      {/* ── Step Into ── */}
      <button
        className={styles.button}
        onClick={() => void actions.stepInto()}
        disabled={!canStep}
        aria-label="Step Into (F11)"
        title="Step Into (F11)"
        type="button"
      >
        {'\u2193'}
      </button>

      {/* ── Step Out ── */}
      <button
        className={styles.button}
        onClick={() => void actions.stepOut()}
        disabled={!canStep}
        aria-label="Step Out (Shift+F11)"
        title="Step Out (Shift+F11)"
        type="button"
      >
        {'\u2191'}
      </button>

      <div className={styles.divider} aria-hidden="true" />

      {/* ── Step Next Bar ── */}
      <button
        className={styles.button}
        onClick={() => void actions.stepNextBar()}
        disabled={!canStep}
        aria-label="Step Next Bar (Ctrl+F10)"
        title="Step Next Bar (Ctrl+F10)"
        type="button"
      >
        {'\u23E9'}
      </button>

      {/* ── Step Backward ── */}
      <button
        className={styles.button}
        onClick={() => void actions.stepBackward()}
        disabled={!canStep}
        aria-label="Step Backward (Ctrl+Shift+F10)"
        title="Step Backward (Ctrl+Shift+F10)"
        type="button"
      >
        {'\u23EA'}
      </button>

      <div className={styles.divider} aria-hidden="true" />

      {/* ── Stop ── */}
      <button
        className={`${styles.button} ${styles.buttonStop}`}
        onClick={() => void actions.stop()}
        disabled={isIdle || isTerminated}
        aria-label="Stop (Shift+F5)"
        title="Stop (Shift+F5)"
        type="button"
      >
        {'\u23F9'}
      </button>

      {/* ── Restart ── */}
      <button
        className={styles.button}
        onClick={() => void actions.restart()}
        disabled={isIdle}
        aria-label="Restart (Ctrl+Shift+F5)"
        title="Restart (Ctrl+Shift+F5)"
        type="button"
      >
        {'\u21BB'}
      </button>

      {/* ── Status & bar info ── */}
      <div className={styles.statusSection}>
        <span className={styles.barInfo} aria-live="polite">
          Bar {currentBar}/{totalBars}
        </span>

        <span className={styles.statusBadge} role="status" aria-label={`Debug status: ${status}`}>
          <span
            className={`${styles.statusDot} ${statusDotClass(status)}`}
            aria-hidden="true"
          />
          {status}
        </span>
      </div>
    </div>
  );
}
