/**
 * usePriceFeed — fetches OHLCV bars from DeskModal's price feed service via FDC3.
 *
 * Raises `deskmodal.GetHistory` intent with the active instrument and timeframe.
 * Returns bars as a JSON string compatible with parse_bars_json() on the Rust side.
 *
 * Resolution: CSV import data > FDC3 price feed > null (no data).
 */
import { useState, useCallback, useRef } from 'react';

const TIMEFRAMES = ['1m', '5m', '15m', '1h', '4h', '1d', '1w', '1M'] as const;
export type PriceFeedTimeframe = (typeof TIMEFRAMES)[number];
export { TIMEFRAMES };

export interface PriceFeedState {
  /** Selected timeframe for data requests. */
  timeframe: PriceFeedTimeframe;
  /** Description of the current data source (for status bar). */
  dataSource: string | null;
  /** True while a GetHistory request is in flight. */
  loading: boolean;
  /** Last error message, or null. */
  error: string | null;
  /** Number of bars returned in the last fetch. */
  barCount: number;
}

export interface PriceFeedActions {
  /** Fetch bars from the price feed service. Returns JSON string or null. */
  fetchBars: (symbol: string, timeframe?: string, limit?: number) => Promise<string | null>;
  /** Set the timeframe. */
  setTimeframe: (tf: PriceFeedTimeframe) => void;
}

export interface UsePriceFeedResult {
  state: PriceFeedState;
  actions: PriceFeedActions;
}

/** Timeout for GetHistory intent (ms). */
const FETCH_TIMEOUT = 15_000;

export function usePriceFeed(): UsePriceFeedResult {
  const [timeframe, setTimeframe] = useState<PriceFeedTimeframe>(() => {
    try {
      const saved = localStorage.getItem('optiscript-timeframe');
      if (saved && (TIMEFRAMES as readonly string[]).includes(saved)) {
        return saved as PriceFeedTimeframe;
      }
    } catch { /* ignore */ }
    return '1h';
  });
  const [dataSource, setDataSource] = useState<string | null>(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [barCount, setBarCount] = useState(0);

  // Abort controller ref for cancelling in-flight requests.
  const abortRef = useRef(0);

  const handleSetTimeframe = useCallback((tf: PriceFeedTimeframe) => {
    setTimeframe(tf);
    try { localStorage.setItem('optiscript-timeframe', tf); } catch { /* ignore */ }
  }, []);

  const fetchBars = useCallback(async (
    symbol: string,
    tf?: string,
    limit = 500,
  ): Promise<string | null> => {
    const fdc3 = window.fdc3;
    if (!fdc3?.raiseIntent) {
      setError('FDC3 not available — import CSV data or connect to DeskModal.');
      return null;
    }

    const requestId = ++abortRef.current;
    setLoading(true);
    setError(null);

    const effectiveTf = tf ?? timeframe;

    try {
      // Discover connected exchanges, then fetch history.
      // Step 1: Get status to find a connected exchange.
      let exchangeId = 'binance'; // fallback
      try {
        const statusCtx: Fdc3Context = {
          type: 'deskmodal.command',
          id: { action: 'getStatus' },
        };
        const statusRes = await fdc3.raiseIntent('deskmodal.GetStatus', statusCtx);
        const statusResult = await statusRes.getResult();
        const exchanges = (statusResult as Record<string, unknown>)?.exchanges;
        if (Array.isArray(exchanges)) {
          const connected = exchanges.find(
            (ex: Record<string, unknown>) => ex.connected === true,
          );
          if (connected) {
            exchangeId = (connected as Record<string, unknown>).exchangeId as string;
          }
        }
      } catch (statusErr) {
        // GetStatus failed — use fallback. Store error for diagnostics.
        const msg = statusErr instanceof Error ? statusErr.message : String(statusErr);
        setError(`Exchange discovery failed (${msg}), trying ${exchangeId}`);
      }

      // Step 2: Fetch history
      const context: Fdc3Context = {
        type: 'deskmodal.command',
        id: { action: 'getHistory' },
        exchangeId,
        symbol,
        interval: effectiveTf,
        limit,
      };

      const resolution = await Promise.race([
        fdc3.raiseIntent('deskmodal.GetHistory', context),
        new Promise<never>((_, reject) =>
          setTimeout(() => reject(new Error('Price feed request timed out')), FETCH_TIMEOUT),
        ),
      ]);

      const result = await Promise.race([
        resolution.getResult(),
        new Promise<never>((_, reject) =>
          setTimeout(() => reject(new Error('Price feed result timed out')), FETCH_TIMEOUT),
        ),
      ]);

      // Check if this request was superseded.
      if (abortRef.current !== requestId) return null;

      if (!result) {
        setLoading(false);
        setError('Price feed returned no data.');
        setDataSource(null);
        setBarCount(0);
        return null;
      }

      // The price feed returns { candles: [{time, open, high, low, close, volume}, ...] }
      // or the result itself may be the array.
      const candles = (result as Record<string, unknown>).candles ?? result;
      if (!Array.isArray(candles) || candles.length === 0) {
        setLoading(false);
        setError(`No bars available for ${symbol} on ${effectiveTf}.`);
        setDataSource(null);
        setBarCount(0);
        return null;
      }

      const barsJson = JSON.stringify(candles);
      setLoading(false);
      setError(null);
      setBarCount(candles.length);
      const exchange = (result as Record<string, unknown>).exchange ??
                       (result as Record<string, unknown>).exchangeId ??
                       exchangeId ?? 'Price Feed';
      setDataSource(`${symbol} · ${effectiveTf.toUpperCase()} · ${candles.length} bars · ${exchange}`);
      return barsJson;
    } catch (err) {
      if (abortRef.current !== requestId) return null;
      const message = err instanceof Error ? err.message : String(err);
      setLoading(false);
      setError(message);
      setDataSource(null);
      setBarCount(0);
      return null;
    }
  }, [timeframe]);

  return {
    state: { timeframe, dataSource, loading, error, barCount },
    actions: { fetchBars, setTimeframe: handleSetTimeframe },
  };
}

export default usePriceFeed;
