/**
 * ComparisonView -- side-by-side diff showing divergence between two
 * script output versions.
 *
 * Displays a summary (total bars, matches, mismatches) and a detail
 * table of divergent bars with their values, deltas, and warning
 * highlighting for mismatches.
 */
import type { ComparisonData } from '../../types/debug';
import styles from './ComparisonView.module.css';

interface ComparisonViewProps {
  /** Comparison result data, or null if no comparison has been run */
  readonly result: ComparisonData | null;
}

export function ComparisonView({ result }: ComparisonViewProps) {
  if (result === null) {
    return (
      <div className={styles.panel} role="region" aria-label="Comparison view">
        <div className={styles.header}>
          <span className={styles.headerTitle}>Comparison</span>
        </div>
        <div className={styles.empty} role="status">
          No comparison data
        </div>
      </div>
    );
  }

  const matchRate = result.totalBars > 0
    ? ((result.matchCount / result.totalBars) * 100).toFixed(1)
    : '0.0';

  return (
    <div className={styles.panel} role="region" aria-label="Comparison view">
      <div className={styles.header}>
        <span className={styles.headerTitle}>Comparison</span>
        <span
          className={`${styles.badge} ${result.mismatchCount === 0 ? styles.badgePass : styles.badgeFail}`}
          role="status"
        >
          {result.mismatchCount === 0 ? 'Match' : 'Divergent'}
        </span>
      </div>

      {/* Summary stats */}
      <div className={styles.summary} role="group" aria-label="Comparison summary">
        <div className={styles.stat}>
          <span className={styles.statLabel}>Total Bars</span>
          <span className={styles.statValue}>{result.totalBars.toLocaleString()}</span>
        </div>
        <div className={styles.stat}>
          <span className={styles.statLabel}>Matches</span>
          <span className={`${styles.statValue} ${styles.statValueMatch}`}>
            {result.matchCount.toLocaleString()}
          </span>
        </div>
        <div className={styles.stat}>
          <span className={styles.statLabel}>Mismatches</span>
          <span className={`${styles.statValue} ${result.mismatchCount > 0 ? styles.statValueMismatch : ''}`}>
            {result.mismatchCount.toLocaleString()}
          </span>
        </div>
        <div className={styles.stat}>
          <span className={styles.statLabel}>Match Rate</span>
          <span className={styles.statValue}>{matchRate}%</span>
        </div>
      </div>

      {/* Divergence detail table */}
      {result.divergences.length > 0 && (
        <div className={styles.tableWrapper}>
          <table
            className={styles.table}
            role="table"
            aria-label="Divergence details"
          >
            <thead>
              <tr>
                <th className={styles.th} scope="col">Bar</th>
                <th className={styles.th} scope="col">Value A</th>
                <th className={styles.th} scope="col">Value B</th>
                <th className={styles.th} scope="col">Delta</th>
              </tr>
            </thead>
            <tbody>
              {result.divergences.map((d) => (
                <tr
                  key={d.barIndex}
                  className={styles.rowDivergent}
                  aria-label={`Bar ${d.barIndex}: A=${d.valueA}, B=${d.valueB}, delta=${d.delta.toFixed(6)}`}
                >
                  <td className={styles.td}>{d.barIndex}</td>
                  <td className={styles.td}>{d.valueA.toFixed(6)}</td>
                  <td className={styles.td}>{d.valueB.toFixed(6)}</td>
                  <td className={`${styles.td} ${styles.tdDelta}`}>
                    {d.delta >= 0 ? '+' : ''}{d.delta.toFixed(6)}
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}
    </div>
  );
}
