/**
 * Focus trap hook for modal dialogs and panels.
 * Cycles Tab/Shift+Tab within the container and closes on Escape.
 */
import { useEffect, useRef, useCallback } from 'react';

const FOCUSABLE_SELECTOR = [
  'a[href]',
  'button:not([disabled])',
  'input:not([disabled])',
  'select:not([disabled])',
  'textarea:not([disabled])',
  '[tabindex]:not([tabindex="-1"])',
].join(', ');

interface UseFocusTrapOptions {
  /** Whether the trap is currently active */
  active: boolean;
  /** Callback when Escape is pressed */
  onEscape?: () => void;
  /** Element to restore focus to when the trap deactivates */
  restoreFocusRef?: React.RefObject<HTMLElement>;
}

/**
 * Returns a callback ref to attach to a container element.
 * When active, traps Tab/Shift+Tab focus cycling within the container
 * and calls onEscape when Escape is pressed.
 */
export function useFocusTrap<T extends HTMLElement>(
  options: UseFocusTrapOptions,
): React.RefCallback<T> {
  const containerRef = useRef<T | null>(null);
  const previousFocusRef = useRef<HTMLElement | null>(null);

  const handleKeyDown = useCallback(
    (event: KeyboardEvent) => {
      if (!options.active || !containerRef.current) return;

      if (event.key === 'Escape') {
        event.preventDefault();
        options.onEscape?.();
        return;
      }

      if (event.key !== 'Tab') return;

      const container = containerRef.current;
      const focusable = Array.from(
        container.querySelectorAll<HTMLElement>(FOCUSABLE_SELECTOR),
      );

      if (focusable.length === 0) {
        event.preventDefault();
        return;
      }

      const firstEl = focusable[0];
      const lastEl = focusable[focusable.length - 1];

      if (event.shiftKey) {
        if (document.activeElement === firstEl) {
          event.preventDefault();
          lastEl.focus();
        }
      } else {
        if (document.activeElement === lastEl) {
          event.preventDefault();
          firstEl.focus();
        }
      }
    },
    [options],
  );

  useEffect(() => {
    if (options.active) {
      previousFocusRef.current = document.activeElement as HTMLElement;

      const container = containerRef.current;
      if (container) {
        const firstFocusable = container.querySelector<HTMLElement>(FOCUSABLE_SELECTOR);
        if (firstFocusable) {
          requestAnimationFrame(() => firstFocusable.focus());
        }
      }

      document.addEventListener('keydown', handleKeyDown);
    }

    return () => {
      document.removeEventListener('keydown', handleKeyDown);

      if (options.active) {
        const restoreTarget = options.restoreFocusRef?.current ?? previousFocusRef.current;
        if (restoreTarget && restoreTarget.isConnected) {
          restoreTarget.focus();
        }
      }
    };
  }, [options.active, handleKeyDown, options.restoreFocusRef]);

  const callbackRef = useCallback((node: T | null) => {
    containerRef.current = node;
  }, []);

  return callbackRef;
}
