/**
 * OrderFlowPanel — Shows order lifecycle events in the strategy debugger.
 *
 * Displays a chronological list of order flow events (placed, filled,
 * cancelled, position opened/closed/reversed) grouped by bar index.
 * Can filter to the current bar or show all bars.
 */
import { useMemo, useState } from 'react';
import type { OrderFlowEntry } from '../../types/debug';
import styles from './OrderFlowPanel.module.css';

interface OrderFlowPanelProps {
  /** All order flow entries from the strategy run */
  readonly entries: readonly OrderFlowEntry[];
  /** Currently selected bar index */
  readonly currentBar: number;
}

/** Display labels for each event type */
const EVENT_LABELS: Record<OrderFlowEntry['eventType'], string> = {
  placed: 'Order Placed',
  filled: 'Order Filled',
  cancelled: 'Order Cancelled',
  opened: 'Position Opened',
  closed: 'Position Closed',
  reversed: 'Position Reversed',
};

/** Unicode icons for each event type */
const EVENT_ICONS: Record<OrderFlowEntry['eventType'], string> = {
  placed: '\u2709',    // envelope
  filled: '\u2713',    // check mark
  cancelled: '\u2715', // cross
  opened: '\u25B2',    // up triangle
  closed: '\u25BC',    // down triangle
  reversed: '\u21C4',  // left-right arrows
};

/** Map event type to its CSS badge class */
function eventBadgeClass(eventType: OrderFlowEntry['eventType']): string {
  switch (eventType) {
    case 'placed':   return styles.badgePlaced;
    case 'filled':   return styles.badgeFilled;
    case 'cancelled': return styles.badgeCancelled;
    case 'opened':   return styles.badgeOpened;
    case 'closed':   return styles.badgeClosed;
    case 'reversed': return styles.badgeReversed;
  }
}

export function OrderFlowPanel({ entries, currentBar }: OrderFlowPanelProps) {
  const [showAll, setShowAll] = useState(false);

  const filteredEntries = useMemo(() => {
    if (showAll) return entries;
    return entries.filter((e) => e.barIndex === currentBar);
  }, [entries, currentBar, showAll]);

  /** Group entries by barIndex for section labels */
  const groupedByBar = useMemo(() => {
    const groups = new Map<number, OrderFlowEntry[]>();
    for (const entry of filteredEntries) {
      const existing = groups.get(entry.barIndex);
      if (existing) {
        existing.push(entry);
      } else {
        groups.set(entry.barIndex, [entry]);
      }
    }
    return groups;
  }, [filteredEntries]);

  const sortedBarIndices = useMemo(
    () => [...groupedByBar.keys()].sort((a, b) => a - b),
    [groupedByBar],
  );

  const handleFilterKeyDown = (event: React.KeyboardEvent) => {
    if (event.key === 'Enter' || event.key === ' ') {
      event.preventDefault();
      setShowAll((prev) => !prev);
    }
  };

  return (
    <div className={styles.panel} role="region" aria-label="Order flow">
      <div className={styles.header}>
        <span className={styles.headerTitle}>Order Flow</span>
        <span className={styles.entryCount} aria-label={`${filteredEntries.length} events`}>
          {filteredEntries.length}
        </span>
        <button
          className={`${styles.filterToggle} ${showAll ? styles.filterToggleActive : ''}`}
          onClick={() => setShowAll((prev) => !prev)}
          onKeyDown={handleFilterKeyDown}
          aria-pressed={showAll}
          aria-label={showAll ? 'Show current bar only' : 'Show all bars'}
          title={showAll ? 'Show current bar only' : 'Show all bars'}
          type="button"
        >
          {showAll ? 'All' : `Bar ${currentBar}`}
        </button>
      </div>

      <div className={styles.content}>
        {filteredEntries.length === 0 ? (
          <div className={styles.empty} role="status">
            No order events{showAll ? '' : ` on bar ${currentBar}`}
          </div>
        ) : (
          <ul className={styles.list} role="list" aria-label="Order flow events">
            {sortedBarIndices.map((barIndex) => {
              const barEntries = groupedByBar.get(barIndex)!;
              return (
                <li key={barIndex} className={styles.barGroup}>
                  <div className={styles.barLabel} aria-hidden="true">
                    Bar {barIndex}
                  </div>
                  <ul className={styles.barEntries} role="list">
                    {barEntries.map((entry, idx) => (
                      <li
                        key={`${entry.orderId}-${entry.eventType}-${idx}`}
                        className={styles.entry}
                        tabIndex={0}
                        aria-label={`${EVENT_LABELS[entry.eventType]}: order ${entry.orderId}, ${entry.details}`}
                      >
                        <span
                          className={`${styles.eventIcon} ${eventBadgeClass(entry.eventType)}`}
                          aria-hidden="true"
                        >
                          {EVENT_ICONS[entry.eventType]}
                        </span>
                        <span className={`${styles.eventType} ${eventBadgeClass(entry.eventType)}`}>
                          {EVENT_LABELS[entry.eventType]}
                        </span>
                        <span className={styles.orderId}>{entry.orderId}</span>
                        <span className={styles.details}>{entry.details}</span>
                      </li>
                    ))}
                  </ul>
                </li>
              );
            })}
          </ul>
        )}
      </div>
    </div>
  );
}
