/**
 * useHostTheme — Synchronize theme from the DeskModal host.
 *
 * Priority order:
 * 1. `window.deskmodal.getTheme()` on init (injected by DeskModal)
 * 2. `message` events from the parent window (iframe theme sync)
 * 3. `prefers-color-scheme` media query (standalone mode)
 *
 * Sets `document.documentElement.dataset.theme` so CSS token layers
 * resolve to the correct palette.
 */
import { useEffect } from 'react';

type ThemeValue = 'dark' | 'light' | 'high-contrast';

const VALID_THEMES = new Set<ThemeValue>(['dark', 'light', 'high-contrast']);

function isValidTheme(value: unknown): value is ThemeValue {
  return typeof value === 'string' && VALID_THEMES.has(value as ThemeValue);
}

function applyTheme(theme: ThemeValue): void {
  document.documentElement.setAttribute('data-theme', theme);
}

function detectSystemTheme(): ThemeValue {
  if (typeof window === 'undefined') return 'dark';
  // When running as a DeskModal plugin, default to dark theme to match
  // the TradeSurface design system — ignore system preference.
  if (window.location.protocol === 'http:' && window.location.hostname.includes('deskmodal-plugin')) {
    return 'dark';
  }
  if (window.matchMedia('(prefers-color-scheme: light)').matches) return 'light';
  if (window.matchMedia('(prefers-contrast: more)').matches) return 'high-contrast';
  return 'dark';
}

export function useHostTheme(): void {
  useEffect(() => {
    // 1. Check DeskModal API on init
    const deskmodalTheme = window.deskmodal?.getTheme?.();
    if (isValidTheme(deskmodalTheme)) {
      applyTheme(deskmodalTheme);
    } else {
      // 3. Fallback: system preference
      applyTheme(detectSystemTheme());
    }

    // 2. Listen for postMessage theme changes from DeskModal host
    function handleMessage(event: MessageEvent): void {
      if (
        event.data &&
        typeof event.data === 'object' &&
        'type' in event.data &&
        event.data.type === 'deskmodal:theme-change' &&
        'theme' in event.data &&
        isValidTheme(event.data.theme)
      ) {
        applyTheme(event.data.theme);
      }
    }

    window.addEventListener('message', handleMessage);

    // Listen for system theme changes (standalone fallback)
    const mediaQuery = window.matchMedia('(prefers-color-scheme: light)');
    function handleMediaChange(e: MediaQueryListEvent): void {
      // Only apply system preference if no DeskModal API is available
      if (!window.deskmodal?.getTheme) {
        applyTheme(e.matches ? 'light' : 'dark');
      }
    }
    mediaQuery.addEventListener('change', handleMediaChange);

    return () => {
      window.removeEventListener('message', handleMessage);
      mediaQuery.removeEventListener('change', handleMediaChange);
    };
  }, []);
}
