/**
 * OptiScript Document Symbol Provider for Monaco Editor
 *
 * Provides outline / breadcrumb support by scanning the document for:
 * - Function definitions: `name(params) =>`
 * - Variable assignments: `name = ...` or `var name = ...` or `varip name = ...`
 * - Type declarations: `type Name`
 * - Method declarations: `method name(params) =>`
 */
import type * as monaco from 'monaco-editor';

/**
 * Creates a Monaco DocumentSymbolProvider for OptiScript.
 */
export function createDocumentSymbolProvider(
  monacoApi: typeof monaco,
): monaco.languages.DocumentSymbolProvider {
  return {
    displayName: 'OptiScript',

    provideDocumentSymbols(
      model: monaco.editor.ITextModel,
    ): monaco.languages.ProviderResult<monaco.languages.DocumentSymbol[]> {
      const symbols: monaco.languages.DocumentSymbol[] = [];
      const lineCount = model.getLineCount();

      for (let lineNumber = 1; lineNumber <= lineCount; lineNumber++) {
        const lineContent = model.getLineContent(lineNumber);
        const trimmed = lineContent.trim();

        // Skip empty lines, comments, and version annotations
        if (
          trimmed.length === 0 ||
          trimmed.startsWith('//') ||
          trimmed.startsWith('//@')
        ) {
          continue;
        }

        // Function definition: funcName(params) =>
        const funcMatch = trimmed.match(
          /^(\w+)\s*\(([^)]*)\)\s*=>/,
        );
        if (funcMatch) {
          const name = funcMatch[1];
          const params = funcMatch[2].trim();
          symbols.push({
            name,
            detail: params ? `(${params})` : '()',
            kind: monacoApi.languages.SymbolKind.Function,
            tags: [],
            range: {
              startLineNumber: lineNumber,
              startColumn: 1,
              endLineNumber: lineNumber,
              endColumn: lineContent.length + 1,
            },
            selectionRange: {
              startLineNumber: lineNumber,
              startColumn: lineContent.indexOf(name) + 1,
              endLineNumber: lineNumber,
              endColumn: lineContent.indexOf(name) + 1 + name.length,
            },
          });
          continue;
        }

        // Method definition: method name(params) =>
        const methodMatch = trimmed.match(
          /^method\s+(\w+)\s*\(([^)]*)\)\s*=>/,
        );
        if (methodMatch) {
          const name = methodMatch[1];
          const params = methodMatch[2].trim();
          symbols.push({
            name,
            detail: params ? `method (${params})` : 'method ()',
            kind: monacoApi.languages.SymbolKind.Method,
            tags: [],
            range: {
              startLineNumber: lineNumber,
              startColumn: 1,
              endLineNumber: lineNumber,
              endColumn: lineContent.length + 1,
            },
            selectionRange: {
              startLineNumber: lineNumber,
              startColumn: lineContent.indexOf(name, lineContent.indexOf('method') + 6) + 1,
              endLineNumber: lineNumber,
              endColumn: lineContent.indexOf(name, lineContent.indexOf('method') + 6) + 1 + name.length,
            },
          });
          continue;
        }

        // Type declaration: type TypeName
        const typeMatch = trimmed.match(/^type\s+(\w+)/);
        if (typeMatch) {
          const name = typeMatch[1];
          symbols.push({
            name,
            detail: 'type',
            kind: monacoApi.languages.SymbolKind.Struct,
            tags: [],
            range: {
              startLineNumber: lineNumber,
              startColumn: 1,
              endLineNumber: lineNumber,
              endColumn: lineContent.length + 1,
            },
            selectionRange: {
              startLineNumber: lineNumber,
              startColumn: lineContent.indexOf(name) + 1,
              endLineNumber: lineNumber,
              endColumn: lineContent.indexOf(name) + 1 + name.length,
            },
          });
          continue;
        }

        // Variable declarations:
        //   var name = ...
        //   varip name = ...
        //   name = ... (top-level, not indented, not inside a function/if/for body)
        const varDeclMatch = trimmed.match(/^(?:var|varip)\s+(\w+)\s*=/);
        if (varDeclMatch) {
          const name = varDeclMatch[1];
          symbols.push({
            name,
            detail: trimmed.startsWith('varip') ? 'varip' : 'var',
            kind: monacoApi.languages.SymbolKind.Variable,
            tags: [],
            range: {
              startLineNumber: lineNumber,
              startColumn: 1,
              endLineNumber: lineNumber,
              endColumn: lineContent.length + 1,
            },
            selectionRange: {
              startLineNumber: lineNumber,
              startColumn: lineContent.indexOf(name) + 1,
              endLineNumber: lineNumber,
              endColumn: lineContent.indexOf(name) + 1 + name.length,
            },
          });
          continue;
        }

        // Top-level variable assignment (no leading whitespace): name = ...
        // Exclude keywords, built-in declarations, and indented lines
        if (!lineContent.startsWith(' ') && !lineContent.startsWith('\t')) {
          const topLevelAssign = trimmed.match(
            /^(\w+)\s*=\s*(?!>)/,
          );
          if (topLevelAssign) {
            const name = topLevelAssign[1];
            // Skip OptiScript keywords and declaration functions
            const reserved = new Set([
              'if', 'else', 'for', 'while', 'switch', 'var', 'varip',
              'type', 'method', 'import', 'export', 'library', 'true', 'false',
              'indicator', 'strategy', 'enum',
            ]);
            if (!reserved.has(name)) {
              symbols.push({
                name,
                detail: 'variable',
                kind: monacoApi.languages.SymbolKind.Variable,
                tags: [],
                range: {
                  startLineNumber: lineNumber,
                  startColumn: 1,
                  endLineNumber: lineNumber,
                  endColumn: lineContent.length + 1,
                },
                selectionRange: {
                  startLineNumber: lineNumber,
                  startColumn: lineContent.indexOf(name) + 1,
                  endLineNumber: lineNumber,
                  endColumn: lineContent.indexOf(name) + 1 + name.length,
                },
              });
            }
          }

          // Destructuring: [name1, name2, ...] = expr
          const destructMatch = trimmed.match(/^\[([^\]]+)\]\s*=/);
          if (destructMatch) {
            const names = destructMatch[1].split(',').map((n) => n.trim()).filter((n) => n.length > 0);
            for (const name of names) {
              symbols.push({
                name,
                detail: 'destructured',
                kind: monacoApi.languages.SymbolKind.Variable,
                tags: [],
                range: {
                  startLineNumber: lineNumber,
                  startColumn: 1,
                  endLineNumber: lineNumber,
                  endColumn: lineContent.length + 1,
                },
                selectionRange: {
                  startLineNumber: lineNumber,
                  startColumn: lineContent.indexOf(name) + 1,
                  endLineNumber: lineNumber,
                  endColumn: lineContent.indexOf(name) + 1 + name.length,
                },
              });
            }
          }
        }
      }

      return symbols;
    },
  };
}
