/**
 * InputPanel — Auto-generated parameter UI from input.* calls in a OptiScript.
 *
 * Renders controls appropriate to each input type: sliders for numeric,
 * checkboxes for bool, color pickers for color, dropdowns for source, etc.
 */
import { useCallback, createRef } from 'react';
import type { InputParameter, SourceOption } from '../../types';
import styles from './InputPanel.module.css';

const SOURCE_OPTIONS: readonly SourceOption[] = [
  'close', 'open', 'high', 'low', 'hl2', 'hlc3', 'ohlc4', 'volume',
];

interface InputPanelProps {
  /** Input parameters extracted from the script */
  inputs: readonly InputParameter[];
  /** Called when an input value changes */
  onInputChange: (id: string, value: number | boolean | string) => void;
  /** Called when all inputs are reset to defaults */
  onReset?: () => void;
}

export function InputPanel({ inputs, onInputChange, onReset }: InputPanelProps) {
  return (
    <div className={styles.panel} role="region" aria-label="Script input parameters">
      <div className={styles.header}>
        <span className={styles.headerTitle}>Inputs</span>
        {onReset && inputs.length > 0 && (
          <button
            className={styles.resetButton}
            onClick={onReset}
            aria-label="Reset all inputs to default values"
            type="button"
          >
            Reset
          </button>
        )}
      </div>

      {inputs.length === 0 ? (
        <div className={styles.empty}>
          No input parameters.
          <br />
          Use <code>input.*()</code> in your script to add parameters.
        </div>
      ) : (
        <div className={styles.inputList} role="group" aria-label="Input parameters">
          {inputs.map((input) => (
            <InputControl
              key={input.id}
              input={input}
              onInputChange={onInputChange}
            />
          ))}
        </div>
      )}
    </div>
  );
}

interface InputControlProps {
  input: InputParameter;
  onInputChange: (id: string, value: number | boolean | string) => void;
}

function InputControl({ input, onInputChange }: InputControlProps) {
  const colorInputRef = createRef<HTMLInputElement>();

  const handleChange = useCallback(
    (value: number | boolean | string) => {
      onInputChange(input.id, value);
    },
    [input.id, onInputChange],
  );

  const labelId = `input-label-${input.id}`;

  return (
    <div className={styles.inputGroup}>
      {input.type !== 'bool' && (
        <label className={styles.inputLabel} id={labelId} htmlFor={`input-${input.id}`}>
          {input.name}
        </label>
      )}
      {input.tooltip && (
        <span className={styles.inputTooltip}>{input.tooltip}</span>
      )}

      {(input.type === 'int' || input.type === 'float') && input.minValue !== undefined && input.maxValue !== undefined ? (
        <NumericSlider input={input} onChange={handleChange} labelId={labelId} />
      ) : (input.type === 'int' || input.type === 'float') ? (
        <NumericInput input={input} onChange={handleChange} labelId={labelId} />
      ) : input.type === 'bool' ? (
        <BoolInput input={input} onChange={handleChange} />
      ) : input.type === 'string' ? (
        input.options && input.options.length > 0 ? (
          <SelectInput input={input} onChange={handleChange} labelId={labelId} />
        ) : (
          <TextInput input={input} onChange={handleChange} labelId={labelId} />
        )
      ) : input.type === 'color' ? (
        <ColorInput input={input} onChange={handleChange} colorInputRef={colorInputRef} />
      ) : input.type === 'source' ? (
        <SourceInput input={input} onChange={handleChange} labelId={labelId} />
      ) : null}
    </div>
  );
}

function NumericSlider({
  input,
  onChange,
  labelId,
}: {
  input: InputParameter;
  onChange: (v: number) => void;
  labelId: string;
}) {
  return (
    <div className={styles.sliderContainer}>
      <input
        type="range"
        id={`input-${input.id}`}
        className={styles.slider}
        min={input.minValue}
        max={input.maxValue}
        step={input.step ?? (input.type === 'int' ? 1 : 0.01)}
        value={input.currentValue as number}
        onChange={(e) => {
          const v = input.type === 'int' ? parseInt(e.target.value, 10) : parseFloat(e.target.value);
          onChange(v);
        }}
        aria-labelledby={labelId}
        aria-valuemin={input.minValue}
        aria-valuemax={input.maxValue}
        aria-valuenow={input.currentValue as number}
      />
      <span className={styles.sliderValue} aria-hidden="true">
        {typeof input.currentValue === 'number'
          ? input.type === 'int'
            ? input.currentValue
            : input.currentValue.toFixed(2)
          : input.currentValue}
      </span>
    </div>
  );
}

function NumericInput({
  input,
  onChange,
  labelId,
}: {
  input: InputParameter;
  onChange: (v: number) => void;
  labelId: string;
}) {
  return (
    <input
      type="number"
      id={`input-${input.id}`}
      className={styles.textInput}
      value={input.currentValue as number}
      step={input.step ?? (input.type === 'int' ? 1 : 0.01)}
      min={input.minValue}
      max={input.maxValue}
      onChange={(e) => {
        const v = input.type === 'int' ? parseInt(e.target.value, 10) : parseFloat(e.target.value);
        if (!isNaN(v)) onChange(v);
      }}
      aria-labelledby={labelId}
    />
  );
}

function BoolInput({
  input,
  onChange,
}: {
  input: InputParameter;
  onChange: (v: boolean) => void;
}) {
  return (
    <label className={styles.checkboxContainer}>
      <input
        type="checkbox"
        id={`input-${input.id}`}
        className={styles.checkbox}
        checked={input.currentValue as boolean}
        onChange={(e) => onChange(e.target.checked)}
        aria-label={input.name}
      />
      <span className={styles.checkboxLabel}>{input.name}</span>
    </label>
  );
}

function SelectInput({
  input,
  onChange,
  labelId,
}: {
  input: InputParameter;
  onChange: (v: string) => void;
  labelId: string;
}) {
  return (
    <select
      id={`input-${input.id}`}
      className={styles.selectInput}
      value={input.currentValue as string}
      onChange={(e) => onChange(e.target.value)}
      aria-labelledby={labelId}
    >
      {input.options?.map((opt) => (
        <option key={opt} value={opt}>
          {opt}
        </option>
      ))}
    </select>
  );
}

function TextInput({
  input,
  onChange,
  labelId,
}: {
  input: InputParameter;
  onChange: (v: string) => void;
  labelId: string;
}) {
  return (
    <input
      type="text"
      id={`input-${input.id}`}
      className={styles.textInput}
      value={input.currentValue as string}
      onChange={(e) => onChange(e.target.value)}
      aria-labelledby={labelId}
    />
  );
}

function ColorInput({
  input,
  onChange,
  colorInputRef,
}: {
  input: InputParameter;
  onChange: (v: string) => void;
  colorInputRef: React.RefObject<HTMLInputElement>;
}) {
  const colorValue = input.currentValue as string;

  return (
    <div className={styles.colorContainer}>
      <button
        className={styles.colorSwatch}
        style={{ backgroundColor: colorValue }}
        onClick={() => colorInputRef.current?.click()}
        aria-label={`Color picker for ${input.name}. Current color: ${colorValue}`}
        type="button"
      />
      <input
        ref={colorInputRef}
        type="color"
        className={styles.colorInput}
        value={colorValue}
        onChange={(e) => onChange(e.target.value)}
        aria-label={`Select color for ${input.name}`}
        tabIndex={-1}
      />
      <span className={styles.colorHex}>{colorValue}</span>
    </div>
  );
}

function SourceInput({
  input,
  onChange,
  labelId,
}: {
  input: InputParameter;
  onChange: (v: string) => void;
  labelId: string;
}) {
  return (
    <select
      id={`input-${input.id}`}
      className={styles.selectInput}
      value={input.currentValue as string}
      onChange={(e) => onChange(e.target.value)}
      aria-labelledby={labelId}
    >
      {SOURCE_OPTIONS.map((src) => (
        <option key={src} value={src}>
          {src}
        </option>
      ))}
    </select>
  );
}
