/**
 * DACP (Desktop Agent Communication Protocol) client for OptiScript.
 *
 * When running inside DeskModal as an iframe plugin, OptiScript communicates
 * with the Rust backend via postMessage through DeskModal's WCP bridge.
 *
 * Flow:
 *  1. On init, sends wcp1Hello to parent window
 *  2. Parent auto-registers the iframe and sends wcp3Handshake
 *  3. dacpInvoke() sends DACP requests and resolves with the response
 */

// ---------------------------------------------------------------------------
// Types
// ---------------------------------------------------------------------------

interface DacpRequest {
  type: string;
  payload: Record<string, unknown>;
  meta: {
    requestUuid: string;
    timestamp: string;
    source: { appId: string };
  };
}

interface DacpResponse {
  type: string;
  payload: { result?: unknown; error?: string };
  meta: {
    requestUuid: string;
    responseUuid?: string;
    source?: { appId: string };
  };
}

// ---------------------------------------------------------------------------
// State
// ---------------------------------------------------------------------------

let initialized = false;
let handshakeReceived = false;
const pendingRequests = new Map<string, {
  resolve: (value: unknown) => void;
  reject: (reason: Error) => void;
}>();

// ---------------------------------------------------------------------------
// UUID helper (no crypto dependency needed)
// ---------------------------------------------------------------------------

function uuid(): string {
  if (typeof crypto !== 'undefined' && crypto.randomUUID) {
    return crypto.randomUUID();
  }
  // Fallback for older browsers
  return 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, (c) => {
    const r = (Math.random() * 16) | 0;
    const v = c === 'x' ? r : (r & 0x3) | 0x8;
    return v.toString(16);
  });
}

// ---------------------------------------------------------------------------
// Message handler
// ---------------------------------------------------------------------------

function handleMessage(event: MessageEvent): void {
  const data = event.data;
  if (!data || typeof data !== 'object' || typeof data.type !== 'string') return;

  // WCP3 Handshake — connection is ready
  if (data.type === 'wcp3Handshake') {
    handshakeReceived = true;
    return;
  }

  // DACP response — match by requestUuid
  const meta = data.meta as DacpResponse['meta'] | undefined;
  if (meta?.requestUuid && pendingRequests.has(meta.requestUuid)) {
    const pending = pendingRequests.get(meta.requestUuid)!;
    pendingRequests.delete(meta.requestUuid);

    const payload = data.payload as DacpResponse['payload'];
    if (payload?.error) {
      pending.reject(new Error(payload.error));
    } else {
      pending.resolve(payload?.result ?? null);
    }
  }
}

// ---------------------------------------------------------------------------
// Initialization
// ---------------------------------------------------------------------------

/**
 * Initialize the DACP connection to the DeskModal host.
 * Safe to call multiple times — only initializes once.
 * Returns true if running in an iframe with a parent to connect to.
 */
export function initDacpClient(): boolean {
  if (initialized) return handshakeReceived || isInIframe();
  initialized = true;

  if (!isInIframe()) return false;

  window.addEventListener('message', handleMessage);

  // Send WCP1 Hello to parent
  window.parent.postMessage(
    {
      type: 'wcp1Hello',
      payload: {
        appId: 'optiscript-editor',
        identityUrl: window.location.href,
        fdc3Version: '2.0',
        implementationMetadata: {
          fdc3Version: '2.0',
          provider: 'OptiScript',
          providerVersion: '0.1.0',
        },
      },
      meta: {
        timestamp: new Date().toISOString(),
      },
    },
    '*',
  );

  return true;
}

function isInIframe(): boolean {
  try {
    return window.self !== window.top;
  } catch {
    return true;
  }
}

// ---------------------------------------------------------------------------
// DACP Invoke
// ---------------------------------------------------------------------------

/**
 * Send a DACP request to the DeskModal host and wait for the response.
 * @param method The method name (e.g., "optiscriptCompile", "optiscriptDebugStart")
 * @param params Parameters to send
 * @param timeoutMs Timeout in milliseconds (default 30s)
 */
export function dacpInvoke(
  method: string,
  params: Record<string, unknown> = {},
  timeoutMs = 30000,
): Promise<unknown> {
  if (!isInIframe()) {
    return Promise.reject(new Error('Not running in iframe'));
  }

  // Auto-init if needed
  if (!initialized) initDacpClient();

  const requestUuid = uuid();

  const request: DacpRequest = {
    type: method,
    payload: params,
    meta: {
      requestUuid,
      timestamp: new Date().toISOString(),
      source: { appId: 'optiscript-editor' },
    },
  };

  return new Promise((resolve, reject) => {
    pendingRequests.set(requestUuid, { resolve, reject });

    // Timeout guard
    const timer = setTimeout(() => {
      if (pendingRequests.has(requestUuid)) {
        pendingRequests.delete(requestUuid);
        reject(new Error(`DACP timeout: ${method} (${timeoutMs}ms)`));
      }
    }, timeoutMs);

    // Clear timeout on resolve/reject
    const originalResolve = resolve;
    const originalReject = reject;
    pendingRequests.set(requestUuid, {
      resolve: (v) => { clearTimeout(timer); originalResolve(v); },
      reject: (e) => { clearTimeout(timer); originalReject(e); },
    });

    window.parent.postMessage(request, '*');
  });
}

/**
 * Check if the DACP connection is available (running in iframe).
 */
export function isDacpAvailable(): boolean {
  return isInIframe();
}
