/**
 * ExecutionTimeline -- horizontal SVG strip showing bar progression.
 *
 * Each bar is a small vertical tick. The current bar is highlighted
 * with an accent-colored marker. Breakpoint bars have red dots.
 * Clicking anywhere navigates to the corresponding bar.
 * The warmup region (first N bars) is lightly shaded.
 */
import { useCallback, useMemo, useRef } from 'react';
import styles from './ExecutionTimeline.module.css';

interface ExecutionTimelineProps {
  /** Total number of bars in the dataset */
  readonly totalBars: number;
  /** Zero-based index of the current bar */
  readonly currentBar: number;
  /** Bar indices that have breakpoints */
  readonly breakpointBars: number[];
  /** Navigate to a specific bar */
  onBarClick: (bar: number) => void;
}

/** SVG viewBox dimensions */
const VIEW_WIDTH = 800;
const VIEW_HEIGHT = 28;
const PADDING_LEFT = 4;
const PADDING_RIGHT = 4;
const TICK_Y_START = 8;
const TICK_Y_END = 22;
const DOT_Y = 5;
const WARMUP_BARS = 10;

export function ExecutionTimeline({
  totalBars,
  currentBar,
  breakpointBars,
  onBarClick,
}: ExecutionTimelineProps) {
  const svgRef = useRef<SVGSVGElement>(null);

  /** X position for a given bar index */
  const barToX = useCallback(
    (bar: number): number => {
      if (totalBars <= 1) return PADDING_LEFT;
      const drawWidth = VIEW_WIDTH - PADDING_LEFT - PADDING_RIGHT;
      return PADDING_LEFT + (bar / (totalBars - 1)) * drawWidth;
    },
    [totalBars],
  );

  /** Current bar X */
  const currentX = useMemo(() => barToX(currentBar), [barToX, currentBar]);

  /** Warmup region width */
  const warmupEndX = useMemo(() => {
    if (totalBars <= WARMUP_BARS) return VIEW_WIDTH - PADDING_RIGHT;
    return barToX(Math.min(WARMUP_BARS, totalBars - 1));
  }, [barToX, totalBars]);

  /** Build tick marks -- sample bars if there are too many to draw individually */
  const ticks = useMemo(() => {
    if (totalBars <= 0) return [];

    const maxTicks = 200;
    const step = totalBars <= maxTicks ? 1 : Math.ceil(totalBars / maxTicks);
    const result: { x: number; bar: number }[] = [];
    for (let i = 0; i < totalBars; i += step) {
      result.push({ x: barToX(i), bar: i });
    }
    // Ensure the last bar is always included
    if (result.length > 0 && result[result.length - 1].bar !== totalBars - 1) {
      result.push({ x: barToX(totalBars - 1), bar: totalBars - 1 });
    }
    return result;
  }, [totalBars, barToX]);

  /** Handle click to navigate */
  const handleClick = useCallback(
    (event: React.MouseEvent<SVGSVGElement>) => {
      const svg = svgRef.current;
      if (!svg || totalBars <= 0) return;

      const rect = svg.getBoundingClientRect();
      const clickX = event.clientX - rect.left;
      const ratio = (clickX / rect.width - PADDING_LEFT / VIEW_WIDTH) /
        ((VIEW_WIDTH - PADDING_LEFT - PADDING_RIGHT) / VIEW_WIDTH);
      const barIndex = Math.round(ratio * (totalBars - 1));
      const clamped = Math.max(0, Math.min(totalBars - 1, barIndex));
      onBarClick(clamped);
    },
    [totalBars, onBarClick],
  );

  /** Keyboard navigation */
  const handleKeyDown = useCallback(
    (event: React.KeyboardEvent<SVGSVGElement>) => {
      if (totalBars <= 0) return;

      if (event.key === 'ArrowRight') {
        event.preventDefault();
        onBarClick(Math.min(totalBars - 1, currentBar + 1));
      } else if (event.key === 'ArrowLeft') {
        event.preventDefault();
        onBarClick(Math.max(0, currentBar - 1));
      } else if (event.key === 'Home') {
        event.preventDefault();
        onBarClick(0);
      } else if (event.key === 'End') {
        event.preventDefault();
        onBarClick(totalBars - 1);
      }
    },
    [totalBars, currentBar, onBarClick],
  );

  return (
    <div className={styles.panel} role="region" aria-label="Execution timeline">
      <div className={styles.header}>
        <span className={styles.headerTitle}>Timeline</span>
        <span className={styles.barLabel}>
          Bar {currentBar} / {totalBars}
        </span>
      </div>

      <div className={styles.chartContainer}>
        {totalBars <= 0 ? (
          <div className={styles.empty} role="status">
            No bar data
          </div>
        ) : (
          <svg
            ref={svgRef}
            className={styles.chart}
            viewBox={`0 0 ${VIEW_WIDTH} ${VIEW_HEIGHT}`}
            preserveAspectRatio="none"
            onClick={handleClick}
            onKeyDown={handleKeyDown}
            tabIndex={0}
            role="slider"
            aria-label={`Execution timeline, bar ${currentBar} of ${totalBars}. Use arrow keys to navigate.`}
            aria-valuemin={0}
            aria-valuemax={totalBars - 1}
            aria-valuenow={currentBar}
          >
            {/* Warmup region shading */}
            {totalBars > WARMUP_BARS && (
              <rect
                x={PADDING_LEFT}
                y={0}
                width={warmupEndX - PADDING_LEFT}
                height={VIEW_HEIGHT}
                className={styles.warmupRegion}
              />
            )}

            {/* Tick marks for sampled bars */}
            {ticks.map((tick) => (
              <line
                key={tick.bar}
                x1={tick.x}
                x2={tick.x}
                y1={TICK_Y_START}
                y2={TICK_Y_END}
                className={styles.tick}
              />
            ))}

            {/* Breakpoint dots */}
            {breakpointBars
              .filter((b) => b >= 0 && b < totalBars)
              .map((bar) => (
                <circle
                  key={`bp-${bar}`}
                  cx={barToX(bar)}
                  cy={DOT_Y}
                  r="3"
                  className={styles.breakpointDot}
                />
              ))}

            {/* Current bar vertical line */}
            <line
              x1={currentX}
              x2={currentX}
              y1={0}
              y2={VIEW_HEIGHT}
              className={styles.currentBarLine}
            />

            {/* Current bar dot */}
            <circle
              cx={currentX}
              cy={VIEW_HEIGHT / 2}
              r="4"
              className={styles.currentBarDot}
            />
          </svg>
        )}
      </div>
    </div>
  );
}
