/**
 * OptiScript Hover Documentation Provider for Monaco Editor
 *
 * Shows function signatures, variable types, and version availability on hover.
 */
import type * as monaco from 'monaco-editor';
import type { OptiVersion } from '../types';
import { BUILTIN_FUNCTIONS, BUILTIN_VARIABLES } from './completions';

/**
 * Creates a Monaco hover provider for OptiScript.
 */
export function createHoverProvider(
  _monacoApi: typeof monaco,
  getVersion: () => OptiVersion,
): monaco.languages.HoverProvider {
  return {
    provideHover(
      model: monaco.editor.ITextModel,
      position: monaco.Position,
    ): monaco.languages.ProviderResult<monaco.languages.Hover> {
      const version = getVersion();
      const word = model.getWordAtPosition(position);
      if (!word) return null;

      const wordText = word.word;
      const range: monaco.IRange = {
        startLineNumber: position.lineNumber,
        endLineNumber: position.lineNumber,
        startColumn: word.startColumn,
        endColumn: word.endColumn,
      };

      // Check if this word follows a namespace dot
      const lineContent = model.getLineContent(position.lineNumber);
      const textBefore = lineContent.substring(0, word.startColumn - 1);
      const nsMatch = textBefore.match(/(\w+)\.\s*$/);

      if (nsMatch) {
        const ns = nsMatch[1];
        // Look up namespace-qualified function
        const fn = BUILTIN_FUNCTIONS.find(
          (f) => f.namespace === ns && f.label === wordText,
        );
        if (fn) {
          return {
            range,
            contents: buildFunctionHover(fn.label, fn.detail, fn.documentation, fn.minVersion, version, ns),
          };
        }
      }

      // Check built-in variables
      const variable = BUILTIN_VARIABLES.find((v) => v.label === wordText);
      if (variable) {
        return {
          range,
          contents: buildVariableHover(variable.label, variable.detail, variable.documentation, variable.minVersion, version),
        };
      }

      // Check top-level functions
      const topFn = BUILTIN_FUNCTIONS.find(
        (f) => !f.namespace && f.label === wordText,
      );
      if (topFn) {
        return {
          range,
          contents: buildFunctionHover(topFn.label, topFn.detail, topFn.documentation, topFn.minVersion, version),
        };
      }

      // Check if hovering over a namespace itself
      const namespaceDescriptions: Record<string, string> = {
        ta: 'Technical Analysis functions (SMA, EMA, RSI, MACD, etc.)',
        math: 'Mathematical functions (abs, ceil, floor, sqrt, etc.)',
        str: 'String manipulation functions',
        array: 'Array data structure functions',
        map: 'Map (dictionary) data structure functions',
        matrix: 'Matrix data structure functions',
        table: 'Table drawing object functions',
        color: 'Color manipulation functions',
        input: 'Input parameter declaration functions',
        request: 'External data request functions (security, financial, etc.)',
        strategy: 'Strategy trading functions (entry, exit, close, etc.)',
        line: 'Line drawing object functions',
        label: 'Label drawing object functions',
        box: 'Box drawing object functions',
        ticker: 'Ticker identifier functions',
        log: 'Opti Logs output functions',
        runtime: 'Runtime control functions',
        session: 'Trading session information',
        syminfo: 'Symbol information variables',
        timeframe: 'Timeframe information variables',
        barstate: 'Bar state information variables',
      };

      if (wordText in namespaceDescriptions) {
        // Check if the next character is a dot (or it's used as a namespace)
        const textAfter = lineContent.substring(word.endColumn - 1);
        if (textAfter.startsWith('.') || nsMatch === null) {
          return {
            range,
            contents: [
              { value: `**${wordText}** namespace` },
              { value: namespaceDescriptions[wordText] },
            ],
          };
        }
      }

      // Check keyword documentation
      const keywordDocs: Record<string, string> = {
        if: 'Conditional expression. Executes the block if the condition is true.',
        else: 'Alternative branch for an `if` expression.',
        for: 'Loop statement. Iterates from a start value to an end value.',
        to: 'Specifies the end value in a `for` loop.',
        by: 'Specifies the step value in a `for` loop.',
        while: 'Loop that repeats while the condition is true. Available since v5.',
        switch: 'Multi-branch conditional expression. Available since v5.',
        var: 'Declares a variable that persists across bars (initialized once). Available since v4.',
        varip: 'Declares a variable that persists even during real-time bar updates. Available since v5.',
        type: 'Declares a user-defined type (UDT). Available since v5.',
        method: 'Declares a method on a type. Available since v5.',
        import: 'Imports a Opti library. Available since v5.',
        export: 'Exports a function from a library. Available since v5.',
        library: 'Declares the script as a Opti library. Available since v5.',
        enum: 'Declares an enumeration type. Available since v6.',
        and: 'Logical AND operator.',
        or: 'Logical OR operator.',
        not: 'Logical NOT operator.',
      };

      if (wordText in keywordDocs) {
        return {
          range,
          contents: [
            { value: `**${wordText}** keyword` },
            { value: keywordDocs[wordText] },
          ],
        };
      }

      return null;
    },
  };
}

/** Builds hover content for a function */
function buildFunctionHover(
  name: string,
  detail: string,
  documentation: string,
  minVersion: OptiVersion,
  currentVersion: OptiVersion,
  namespace?: string,
): monaco.IMarkdownString[] {
  const qualifiedName = namespace ? `${namespace}.${name}` : name;
  const contents: monaco.IMarkdownString[] = [
    { value: `\`\`\`optiscript\n${detail}\n\`\`\`` },
    { value: documentation },
  ];

  if (minVersion > 2) {
    const available = currentVersion >= minVersion;
    const marker = available ? '' : ' (not available in current version)';
    contents.push({
      value: `*Available since OptiScript v${minVersion}*${marker}`,
    });
  }

  // Suppress unused variable lint — qualifiedName is for potential future use
  void qualifiedName;

  return contents;
}

/** Builds hover content for a variable */
function buildVariableHover(
  name: string,
  detail: string,
  documentation: string,
  minVersion: OptiVersion,
  currentVersion: OptiVersion,
): monaco.IMarkdownString[] {
  const contents: monaco.IMarkdownString[] = [
    { value: `\`\`\`optiscript\n${name}: ${detail}\n\`\`\`` },
    { value: documentation },
  ];

  if (minVersion > 2) {
    const available = currentVersion >= minVersion;
    const marker = available ? '' : ' (not available in current version)';
    contents.push({
      value: `*Available since OptiScript v${minVersion}*${marker}`,
    });
  }

  return contents;
}
