/** Map completion item kinds to Monaco kinds */
function toMonacoKind(
  kind: OptiCompletionItem['kind'],
  monacoApi: typeof monaco,
): monaco.languages.CompletionItemKind {
  switch (kind) {
    case 'function': return monacoApi.languages.CompletionItemKind.Function;
    case 'variable': return monacoApi.languages.CompletionItemKind.Variable;
    case 'keyword': return monacoApi.languages.CompletionItemKind.Keyword;
    case 'constant': return monacoApi.languages.CompletionItemKind.Constant;
    case 'method': return monacoApi.languages.CompletionItemKind.Method;
    case 'property': return monacoApi.languages.CompletionItemKind.Property;
  }
}

/**
 * Creates a Monaco completion provider for OptiScript.
 */
export function createCompletionProvider(
  monacoApi: typeof monaco,
  getVersion: () => OptiVersion,
): monaco.languages.CompletionItemProvider {
  return {
    triggerCharacters: ['.'],

    provideCompletionItems(
      model: monaco.editor.ITextModel,
      position: monaco.Position,
    ): monaco.languages.ProviderResult<monaco.languages.CompletionList> {
      const version = getVersion();
      const word = model.getWordUntilPosition(position);
      const range: monaco.IRange = {
        startLineNumber: position.lineNumber,
        endLineNumber: position.lineNumber,
        startColumn: word.startColumn,
        endColumn: word.endColumn,
      };

      // Check if we're after a dot (namespace context)
      const lineContent = model.getLineContent(position.lineNumber);
      const textBeforeCursor = lineContent.substring(0, position.column - 1);
      const dotMatch = textBeforeCursor.match(/(\w+)\.\s*$/);

      const suggestions: monaco.languages.CompletionItem[] = [];

      if (dotMatch) {
        // Namespace-qualified completions
        const ns = dotMatch[1];
        for (const item of BUILTIN_FUNCTIONS) {
          if (item.namespace === ns && item.minVersion <= version) {
            suggestions.push({
              label: item.label,
              kind: toMonacoKind(item.kind, monacoApi),
              detail: item.detail,
              documentation: { value: item.documentation },
              insertText: item.insertText,
              insertTextRules: monacoApi.languages.CompletionItemInsertTextRule.InsertAsSnippet,
              range,
            });
          }
        }
      } else {
        // Global completions: keywords + variables + top-level functions
        const keywords = getKeywordsForVersion(version);
        for (const kw of keywords) {
          suggestions.push({
            label: kw,
            kind: monacoApi.languages.CompletionItemKind.Keyword,
            detail: 'keyword',
            documentation: { value: `OptiScript keyword: \`${kw}\`` },
            insertText: kw,
            range,
          });
        }

        for (const item of BUILTIN_VARIABLES) {
          if (item.minVersion <= version) {
            suggestions.push({
              label: item.label,
              kind: toMonacoKind(item.kind, monacoApi),
              detail: item.detail,
              documentation: { value: item.documentation },
              insertText: item.insertText,
              range,
            });
          }
        }

        // Top-level functions (no namespace)
        for (const item of BUILTIN_FUNCTIONS) {
          if (!item.namespace && item.minVersion <= version) {
            suggestions.push({
              label: item.label,
              kind: toMonacoKind(item.kind, monacoApi),
              detail: item.detail,
              documentation: { value: item.documentation },
              insertText: item.insertText,
              insertTextRules: monacoApi.languages.CompletionItemInsertTextRule.InsertAsSnippet,
              range,
            });
          }
        }

        // Namespace prefixes
        const namespaces = ['ta', 'math', 'str', 'array', 'map', 'matrix', 'table',
          'color', 'input', 'request', 'strategy', 'line', 'label', 'box',
          'ticker', 'log', 'runtime'];
        for (const ns of namespaces) {
          suggestions.push({
            label: ns,
            kind: monacoApi.languages.CompletionItemKind.Module,
            detail: `${ns} namespace`,
            documentation: { value: `OptiScript \`${ns}\` namespace. Type \`${ns}.\` to see available functions.` },
            insertText: ns,
            range,
          });
        }
      }

      // Add user-defined symbol completions (functions and variables from the current document)
      if (!dotMatch) {
        const currentWord = word.word.toLowerCase();
        const text = model.getValue();
        const seenNames = new Set<string>();

        // Extract function definitions: funcName(
        const funcRegex = /^(\w+)\s*\([^)]*\)\s*=>/gm;
        let funcMatch2: RegExpExecArray | null;
        while ((funcMatch2 = funcRegex.exec(text)) !== null) {
          const name = funcMatch2[1];
          if (!seenNames.has(name) && name.toLowerCase() !== currentWord) {
            seenNames.add(name);
            suggestions.push({
              label: name,
              kind: monacoApi.languages.CompletionItemKind.Function,
              detail: 'user function',
              documentation: { value: `User-defined function \`${name}\`` },
              insertText: name,
              range,
            });
          }
        }

        // Extract variable assignments: varName = (including var/varip prefixed)
        const varRegex = /^(?:var(?:ip)?\s+)?(\w+)\s*=[^>=]/gm;
        let varMatch: RegExpExecArray | null;
        const reserved = new Set([
          'if', 'else', 'for', 'while', 'switch', 'var', 'varip',
          'type', 'method', 'import', 'export', 'library', 'true', 'false',
          'indicator', 'strategy', 'enum', 'and', 'or', 'not',
        ]);
        while ((varMatch = varRegex.exec(text)) !== null) {
          const name = varMatch[1];
          if (
            !seenNames.has(name) &&
            !reserved.has(name) &&
            name.toLowerCase() !== currentWord
          ) {
            seenNames.add(name);
            suggestions.push({
              label: name,
              kind: monacoApi.languages.CompletionItemKind.Variable,
              detail: 'user variable',
              documentation: { value: `User-defined variable \`${name}\`` },
              insertText: name,
              range,
            });
          }
        }
      }

      return { suggestions };
    },
  };
}

/** Exported for use in hover provider */
export { BUILTIN_FUNCTIONS, BUILTIN_VARIABLES };
