/**
 * ProfilerHeatmap -- displays per-line hit counts as a heat-colored grid.
 *
 * Maps hit counts to a 5-level heat color gradient from cold (green)
 * through warm (orange) to hot (red) using the profiler design tokens.
 * Sortable by count (descending) or line number (ascending).
 */
import { useMemo, useState } from 'react';
import type { HitCountEntry } from '../../types/debug';
import styles from './ProfilerHeatmap.module.css';

interface ProfilerHeatmapProps {
  /** Per-line hit counts */
  readonly hitCounts: readonly HitCountEntry[];
  /** Maximum hit count (used to normalize bar widths) */
  readonly maxCount: number;
}

type SortMode = 'count' | 'line';

/** Map a ratio (0..1) to one of 5 heat level CSS classes */
function heatLevelClass(ratio: number): string {
  if (ratio <= 0.2) return styles.heatLevel1;
  if (ratio <= 0.4) return styles.heatLevel2;
  if (ratio <= 0.6) return styles.heatLevel3;
  if (ratio <= 0.8) return styles.heatLevel4;
  return styles.heatLevel5;
}

export function ProfilerHeatmap({ hitCounts, maxCount }: ProfilerHeatmapProps) {
  const [sortMode, setSortMode] = useState<SortMode>('count');

  const sorted = useMemo(() => {
    const entries = [...hitCounts];
    if (sortMode === 'count') {
      entries.sort((a, b) => b.count - a.count);
    } else {
      entries.sort((a, b) => a.line - b.line);
    }
    return entries;
  }, [hitCounts, sortMode]);

  const safeMax = maxCount > 0 ? maxCount : 1;

  const handleSortKeyDown = (event: React.KeyboardEvent, mode: SortMode) => {
    if (event.key === 'Enter' || event.key === ' ') {
      event.preventDefault();
      setSortMode(mode);
    }
  };

  return (
    <div className={styles.panel} role="region" aria-label="Profiler heatmap">
      <div className={styles.header}>
        <span className={styles.headerTitle}>Profiler Heatmap</span>
        <div className={styles.sortControls} role="group" aria-label="Sort order">
          <button
            className={`${styles.sortButton} ${sortMode === 'count' ? styles.sortButtonActive : ''}`}
            onClick={() => setSortMode('count')}
            onKeyDown={(e) => handleSortKeyDown(e, 'count')}
            aria-pressed={sortMode === 'count'}
            type="button"
          >
            Count
          </button>
          <button
            className={`${styles.sortButton} ${sortMode === 'line' ? styles.sortButtonActive : ''}`}
            onClick={() => setSortMode('line')}
            onKeyDown={(e) => handleSortKeyDown(e, 'line')}
            aria-pressed={sortMode === 'line'}
            type="button"
          >
            Line
          </button>
        </div>
      </div>

      {sorted.length === 0 ? (
        <div className={styles.empty} role="status">
          No profiler data
        </div>
      ) : (
        <div
          className={styles.grid}
          role="grid"
          aria-label="Hit count heatmap"
          aria-rowcount={sorted.length}
        >
          <div className={styles.gridHeaderRow} role="row" aria-rowindex={1}>
            <span className={styles.gridColHeader} role="columnheader">Line</span>
            <span className={styles.gridColHeader} role="columnheader">Count</span>
            <span className={styles.gridColHeader} role="columnheader">Heat</span>
          </div>
          {sorted.map((entry, index) => {
            const ratio = entry.count / safeMax;
            const widthPercent = Math.max(ratio * 100, 2);

            return (
              <div
                key={entry.line}
                className={styles.gridRow}
                role="row"
                aria-rowindex={index + 2}
                tabIndex={0}
                aria-label={`Line ${entry.line}: ${entry.count} hits`}
              >
                <span className={styles.lineNumber} role="gridcell">
                  {entry.line}
                </span>
                <span className={styles.hitCount} role="gridcell">
                  {entry.count.toLocaleString()}
                </span>
                <span className={styles.barCell} role="gridcell">
                  <span
                    className={`${styles.bar} ${heatLevelClass(ratio)}`}
                    style={{ width: `${widthPercent}%` }}
                    aria-hidden="true"
                  />
                </span>
              </div>
            );
          })}
        </div>
      )}
    </div>
  );
}
